"use strict";exports.id=817,exports.ids=[817],exports.modules={80817:(a,b,c)=>{c.d(b,{SA:()=>e,ut:()=>g,DU:()=>f});let d={en:{seo:{metaTitle:"SEO Agency for Lead Generation | KINEXIS Digital",metaDescription:"SEO focused on keywords that book calls, not vanity rankings. Technical audits, content, and links tied to revenue. Plans from $2,500/mo.",hero:{label:"SEO Services",line1:"Rank for the searches",line2:"that actually convert.",subtitle:"Search rankings built around the keywords your buyers use right before they hire someone. Technical work, content, and links all mapped to revenue, not audit scores."},answerBlock:"Our SEO work covers technical audits, keyword research, on-page fixes, content, and links. Most clients invest $2,500 to $8,000 per month depending on competition and scope. Ranking movement usually shows up in 60 to 90 days. Lead growth follows around months four to six.",problem:{title:"Most businesses rank for terms that never convert",intro:"You can sit on page one and still hear crickets. That usually means you are winning searches from people who were never going to hire you.",points:["Monthly reports full of impressions while qualified leads stay flat.","Blog posts go live with no keyword intent and no clear next step for the reader.","Technical fixes stack up in a backlog while the pages that actually sell stay broken.","Link building chases domain authority scores instead of relevance in your market."]},solution:{title:"SEO built around keywords that buy",intro:"We start with what your best customers search before they call a competitor. Every page, link, and fix supports that path.",points:["Keyword maps tied to service pages and content that moves people toward a booked call.","Technical work prioritized by revenue impact, not audit score.","Content aimed at commercial and transactional intent, not informational fluff.","Reporting on leads, cost per acquisition, and pipeline. Rankings are context, not the headline."]},deliverables:{title:"What you get with our SEO program",subtitle:"Six deliverables. One organic growth system.",items:[{title:"Technical SEO Audit and Fix Plan",description:"Crawl analysis, Core Web Vitals review, indexation fixes, and schema markup on priority revenue pages."},{title:"Keyword and Content Strategy",description:"Buyer-intent keyword research, content gaps, and a publishing calendar mapped to your sales funnel."},{title:"On-Page Optimization",description:"Title tags, headings, internal links, and page structure updates on pages that drive leads."},{title:"Content Production",description:"Service pages, blog posts, and landing pages written for search intent and conversion."},{title:"Link Building and Digital PR",description:"Outreach, guest placements, and authority links from relevant sites in your industry."},{title:"Monthly Performance Reporting",description:"Rankings, traffic, leads, and pipeline tied to specific keywords and pages you can act on."}]},comparison:{title:"SEO Agency vs. In-House Hire",subtitle:"See what you get when you partner with a dedicated SEO team.",layout:"ledger",columns:[{header:"In-House SEO Manager"},{header:"KINEXIS SEO",highlight:!0}],rows:[{label:"Monthly cost",values:["$6,000 to $9,000 salary plus tools","$2,500 to $8,000 all-in"]},{label:"Time to launch",values:["60 to 90 days to hire and onboard","2 to 3 weeks to start"]},{label:"Technical + content + links",values:["One person, limited bandwidth","Full team across all three pillars"]},{label:"Tool stack",values:["$500 to $1,200/mo on top of salary","Included in your retainer"]},{label:"Revenue reporting",values:["Often traffic-focused","Lead and pipeline attribution built in"]},{label:"Flexibility",values:["Fixed headcount","Scale up or down as results demand"]}]},extraFaqs:[{question:"How much does SEO cost with KINEXIS?",answer:"Most SEO retainers run $2,500 to $8,000 per month based on market competition, number of locations, and content volume. We give you a fixed scope and price after a strategy call, with no hidden add-ons."},{question:"How long until SEO produces leads?",answer:"Expect early ranking movement in 60 to 90 days. Consistent lead growth usually shows up between months 4 and 6. Competitive industries may take longer, but we track progress monthly so you see what is working."},{question:"Do you guarantee first-page rankings?",answer:"No ethical agency guarantees specific positions. We guarantee a clear strategy, consistent execution, and reporting tied to leads and revenue. Our clients have seen organic lead growth of 80% to 140% within the first year."},{question:"What is included in your SEO audits?",answer:"Technical crawl issues, page speed, mobile usability, indexation, on-page gaps, competitor keyword overlap, and backlink profile review. You get a prioritized fix list ranked by revenue impact."}]},"local-seo":{metaTitle:"Local SEO for Map Pack Rankings & Calls | KINEXIS Digital",metaDescription:"Local SEO for Google Maps, reviews, citations, and location pages. Win the map pack and turn nearby searches into calls. Plans from $2,000/mo.",hero:{label:"Local SEO Services",line1:"Show up in maps",line2:"when locals actually search.",subtitle:"Local visibility for businesses that live and die by proximity. Map pack rankings, Google Business Profile, citations, reviews, and location pages. All working together so nearby searches become calls."},answerBlock:"Local SEO services include Google Business Profile optimization, citation building, review strategy, location page development, and local link acquisition. Retainers typically start at $2,000 to $5,000 per month for single-location businesses and scale for multi-location brands. Map pack movement often appears within 30 to 60 days.",problem:{title:"You can be five minutes away and still invisible on Google Maps",intro:"Most service businesses get found through the map pack. If your profile is half-finished or your business name shows up five different ways online, those jobs go to whoever looks more established.",points:["Google Business Profile sits on default settings with the wrong categories and outdated photos.","Your name, address, and phone number do not match across directories, which confuses Google.","Competitors add reviews every week while yours stall at a handful from 2022.","City landing pages are thin or missing, so neighborhood searches skip you for national brands."]},solution:{title:"Local search treated market by market",intro:"Each location gets its own plan. Profile work, citations, reviews, and on-site content stack together so you win the searches that turn into same-day calls.",points:["GBP tuned for categories, services, posts, photos, and Q&A that match how people search in your area.","Citation cleanup plus new listings on the directories that actually matter in your trade.","Review systems that keep new feedback coming in without breaking platform rules.","Location pages with real local detail, schema, and internal links that rank for city and neighborhood terms."]},deliverables:{title:"What you get with our local SEO program",subtitle:"Map pack visibility, calls, and booked jobs.",items:[{title:"Google Business Profile Management",description:"Profile optimization, weekly posts, photo updates, service listings, and performance tracking."},{title:"Citation Audit and Building",description:"NAP consistency fixes and new listings on industry-relevant directories and data aggregators."},{title:"Review Strategy and Monitoring",description:"Review request workflows, response templates, and reputation tracking by location."},{title:"Location Page Development",description:"Unique city and neighborhood pages with local content, schema, and internal linking."},{title:"Local Link Building",description:"Sponsorships, local partnerships, and community placements that build geographic authority."},{title:"Local Rank and Lead Reporting",description:"Map pack tracking, call tracking, direction requests, and lead volume by location."}]},comparison:{title:"Local SEO: DIY vs. Agency",subtitle:"Compare managing local search yourself against a dedicated local SEO program.",layout:"ledger",columns:[{header:"DIY / Generic SEO Tool"},{header:"KINEXIS Local SEO",highlight:!0}],rows:[{label:"GBP expertise",values:["Basic listing setup","Ongoing optimization and posting"]},{label:"Citation management",values:["Manual, error-prone updates","Automated monitoring and cleanup"]},{label:"Review velocity",values:["Sporadic, no system","Structured review generation process"]},{label:"Multi-location support",values:["One profile at a time","Centralized strategy per market"]},{label:"Local content",values:["Duplicate city pages","Unique location pages with local signals"]},{label:"Results timeline",values:["Unpredictable","Map pack gains often within 30 to 60 days"]}]},extraFaqs:[{question:"How is local SEO different from regular SEO?",answer:'Regular SEO chases rankings on standard search results. Local SEO is built for the map pack: Google Business Profile, citations, reviews, and location pages. If your customers search by city or "near me," you need both, but local is what puts you on the map.'},{question:"How much does local SEO cost?",answer:"Single-location businesses usually run $2,000 to $5,000 per month. Multi-location brands scale from $3,500 to $10,000+ based on how many markets you cover and how tight the competition is. We quote after looking at your locations and current visibility."},{question:"How many Google reviews do I need?",answer:"There is no magic number. In competitive markets, staying in the top three map spots often means 50 to 100+ reviews. We focus on steady monthly volume and thoughtful responses, not a one-time push that fades."},{question:"Can you manage multiple Google Business Profiles?",answer:"Yes. We run multi-location accounts with separate content, review workflows, and reporting per market. Franchises and multi-branch operators are a big part of what we do."}]},"ppc-management":{metaTitle:"Multi-Channel PPC Management | Google, Meta & More | KINEXIS",metaDescription:"One team managing Google, Meta, LinkedIn, and Microsoft Ads. Shared tracking, weekly budget shifts, and ROAS you can trust. From 15% of spend or $2,500/mo min.",hero:{label:"PPC Management",line1:"One team running",line2:"every channel you pay for.",subtitle:"One team managing Google, Meta, LinkedIn, and Microsoft. Shared goals, shared tracking, and weekly budget moves based on what your CRM confirms as real pipeline."},answerBlock:"PPC management covers strategy, campaign setup, bid optimization, creative coordination, and conversion tracking across Google, Meta, LinkedIn, and Microsoft Ads. Fees are typically 15% of ad spend with a $2,500 monthly minimum, or a flat retainer for larger accounts. Most accounts reach stable CPL within 45 to 60 days of launch.",problem:{title:"Separate ad accounts usually compete with each other",intro:"Google and Meta often run in silos. Nobody compares cost per lead across channels, tracking breaks between platforms and your CRM, and budget stays stuck on whatever looked good in a slide deck.",points:["Spend keeps flowing to underperforming platforms because no one owns the full picture.","Each platform counts conversions differently, so ROAS numbers do not match reality.","Creative and landing pages get rebuilt per channel with no shared testing plan.","Freelancers or internal owners manage one platform each, which slows decisions and duplicates work."]},solution:{title:"Paid media run like one program",intro:"Shared goals, shared tracking, and weekly budget moves based on what your CRM confirms as qualified pipeline.",points:["Budget allocation tied to cost per qualified lead, not platform preference or politics.","Conversion tracking from click to CRM so you see true ROAS by channel and campaign.","Creative and landing page coordination so messaging stays consistent across search and social.","Weekly optimization across every account instead of monthly check-ins on one platform."]},deliverables:{title:"What you get with PPC management",subtitle:"Everything you need to run Google, Meta, LinkedIn, and Microsoft as one coordinated program.",items:[{title:"Cross-Channel Strategy and Budget Plan",description:"Channel mix recommendations, monthly budget allocation, and KPI targets by platform."},{title:"Campaign Build and Launch",description:"Account structure, audience targeting, ad copy, and extensions across Google, Meta, LinkedIn, and Microsoft."},{title:"Conversion Tracking Setup",description:"GA4, platform pixels, CRM integration, and offline conversion import for accurate attribution."},{title:"Weekly Bid and Budget Optimization",description:"Ongoing bid adjustments, budget shifts, negative keyword management, and audience refinements."},{title:"Creative Testing Framework",description:"Ad copy and creative rotation with structured A/B tests and performance benchmarks."},{title:"Unified Performance Dashboard",description:"Cross-channel reporting on spend, CPL, ROAS, and pipeline value in one view."}]},comparison:{title:"Multi-Channel PPC: Separate Managers vs. KINEXIS",subtitle:"What changes when one team owns your entire paid media program.",layout:"impact",columns:[{header:"Separate Channel Managers"},{header:"KINEXIS PPC Management",highlight:!0}],rows:[{label:"Strategy alignment",values:["Each platform optimizes in isolation","Unified goals and shared KPIs"]},{label:"Budget flexibility",values:["Siloed budgets, slow to shift","Weekly reallocation to best performers"]},{label:"Tracking consistency",values:["Different definitions of a conversion","One tracking framework across all channels"]},{label:"Management cost",values:["15 to 20% per platform adds up","Single fee structure, lower total overhead"]},{label:"Reporting",values:["Multiple dashboards, conflicting numbers","One dashboard with cross-channel ROAS"]},{label:"Decision speed",values:["Coordination meetings slow changes","Same-day budget and bid adjustments"]}]},extraFaqs:[{question:"What platforms do you manage under PPC management?",answer:"Google Ads, Meta (Facebook and Instagram), LinkedIn Ads, and Microsoft Ads. We coordinate budgets and reporting across all four. If you only need one platform, our Google Ads or Meta Ads services may fit better."},{question:"How is PPC management priced?",answer:"Typically 15% of monthly ad spend with a $2,500 minimum retainer, or a flat fee for accounts spending $50,000+ per month. Ad spend bills directly to the platforms on your accounts. You always own the accounts."},{question:"What ad spend level do you require?",answer:"We work best when total spend across channels is $5,000 to $100,000+ per month. Below $5,000, a single-channel program is usually more efficient."},{question:"How is PPC management different from your paid ads service?",answer:"Paid ads is the starting point for businesses exploring paid media. PPC management is the full multi-channel program: cross-platform strategy, unified tracking, and ongoing optimization across Google, Meta, LinkedIn, and Microsoft."}]},"google-ads":{metaTitle:"Google Ads Management Agency | Search & PMax | KINEXIS Digital",metaDescription:"Google Ads management for Search, Shopping, and Performance Max. Conversion tracking, Quality Score work, and ROAS-focused campaigns. From $1,500/mo management.",hero:{label:"Google Ads Management",line1:"Google Ads that protect",line2:"your margin, not Google's.",subtitle:"We audit, restructure, and manage Google accounts around one number: cost per qualified lead. Not clicks. Not impressions. The leads your sales team actually wants to talk to."},answerBlock:"Google Ads management covers account audit, campaign structure, keywords, ad copy, bids, Quality Score, and conversion tracking for Search, Shopping, and PMax. Management starts at $1,500 per month plus ad spend. Most accounts see CPL stabilize within 30 to 45 days.",problem:{title:"Most Google Ads accounts bleed budget on the wrong searches",intro:"Google makes spending easy. Knowing what actually drives revenue is the hard part. Most accounts we audit have the same structural problems.",points:["Broad match and auto-apply recommendations send budget to searches that will never convert.","Conversion tracking counts form fills and page views instead of leads your sales team confirms.","Brand, competitor, and generic terms sit in the same campaign, so you cannot tell what is working.","Landing pages do not match the ad promise, which kills Quality Score and raises your cost per click."]},solution:{title:"Google Ads built for Quality Score and ROAS",intro:"We restructure around search intent, tighten tracking to qualified conversions, and adjust bids based on what your CRM confirms as real pipeline.",points:["Separate campaigns for brand, competitor, and high-intent generic keywords.","Weekly search term reviews and negative keyword lists to cut waste before it compounds.","Ad copy and landing page alignment that improves Quality Score and lowers CPC.","Bid strategies tied to offline conversion data when your sales cycle runs longer than the click."]},deliverables:{title:"Google Ads management deliverables",subtitle:"Search, Shopping, and Performance Max. Built for ROAS, not for Google's quarterly targets.",items:[{title:"Account Audit and Restructure",description:"Full review of campaigns, ad groups, keywords, match types, and conversion actions with a rebuild plan."},{title:"Keyword Research and Negative Lists",description:"High-intent keyword targets plus ongoing negative keyword lists to block irrelevant traffic."},{title:"Ad Copy and Extension Management",description:"Responsive search ads, callouts, sitelinks, and structured snippets tested on a regular cadence."},{title:"Performance Max and Shopping Setup",description:"Feed optimization, asset groups, audience signals, and listing group structure for e-commerce accounts."},{title:"Conversion Tracking and Attribution",description:"GA4, Google Tag Manager, enhanced conversions, and CRM integration for accurate lead tracking."},{title:"Weekly Optimization and Reporting",description:"Bid adjustments, budget pacing, search term reviews, and monthly ROAS and CPL reporting."}]},comparison:{title:"Google Ads: Self-Managed vs. KINEXIS",subtitle:"Compare running Google Ads in-house against a dedicated management team.",layout:"impact",columns:[{header:"Self-Managed / Freelancer"},{header:"KINEXIS Google Ads",highlight:!0}],rows:[{label:"Account structure",values:["Flat campaigns, mixed intent","Segmented by intent and funnel stage"]},{label:"Optimization frequency",values:["Monthly or when budget runs out","Weekly search term and bid reviews"]},{label:"Conversion tracking",values:["Page views counted as conversions","Qualified lead tracking with CRM sync"]},{label:"Quality Score focus",values:["Rarely monitored","Active ad and landing page alignment"]},{label:"Shopping / PMax expertise",values:["Limited feed and asset experience","Dedicated e-commerce campaign management"]},{label:"Typical CPL improvement",values:["Baseline or increasing","20 to 40% reduction within 90 days"]}]},extraFaqs:[{question:"How much does Google Ads management cost?",answer:"Management fees start at $1,500 per month for accounts under $10,000 in ad spend. Larger accounts are priced at 12 to 15% of spend. Your ad budget is paid directly to Google. We recommend a minimum $3,000 monthly ad spend to gather enough data for optimization."},{question:"Do you manage Performance Max campaigns?",answer:"Yes. We build and optimize Performance Max with proper asset groups, audience signals, and feed data for e-commerce. We also monitor search term insights and brand traffic to prevent PMax from cannibalizing your Search campaigns."},{question:"How quickly will I see results from Google Ads?",answer:"Search campaigns often produce leads within the first week of launch. Stable, optimized CPL typically takes 30 to 45 days as we refine keywords, negatives, and bids. Shopping and PMax may need 2 to 3 weeks for the algorithm to stabilize."},{question:"Will I own my Google Ads account?",answer:"Always. We work inside your account with full admin access. If you leave, you keep every campaign, keyword list, and conversion setup we built."}]},"meta-ads":{metaTitle:"Meta Ads Management Agency | Facebook & Instagram | KINEXIS Digital",metaDescription:"Meta Ads management for Facebook and Instagram. Creative testing, audience segmentation, and ROAS-focused campaigns. Management from $1,500/mo plus ad spend.",hero:{label:"Meta Ads Management",line1:"Meta Ads that keep",line2:"working after launch week.",subtitle:"Facebook and Instagram campaigns built to stay profitable past the first two weeks, with a structured creative testing system that keeps the algorithm fed and CPM under control."},answerBlock:"Meta Ads management covers audience research, campaign structure, creative testing, retargeting funnels, and pixel-based tracking on Facebook and Instagram. Management starts at $1,500 per month. Most accounts need $3,000 to $15,000 in monthly ad spend and two to four weeks of creative testing to find stable ROAS.",problem:{title:"Why Meta ad accounts stall after the first good week",intro:"Meta rewards fresh creative and clean audience separation. Most businesses launch a handful of ads, see early results, then watch CPM climb while ROAS drops.",points:["Creative fatigue sets in because nobody is producing and testing new variations on a schedule.","Prospecting and retargeting audiences overlap, which inflates costs and muddies attribution.","Pixel and CAPI tracking miss conversions, so the algorithm optimizes toward the wrong events.","Budget goes to broad targeting without lookalikes or interest stacks built from customer data."]},solution:{title:"Meta campaigns with structured creative testing",intro:"We build prospecting and retargeting funnels with a creative pipeline that keeps ads fresh and audiences clean so the algorithm has good data to work with.",points:["Campaign structure that separates cold prospecting, warm engagement, and hot retargeting.","Creative testing sprints with three to five new ad variations every two weeks.","Conversions API and pixel setup that feeds accurate purchase and lead data back to Meta.","Lookalike and custom audiences built from your CRM, site visitors, and past purchasers."]},deliverables:{title:"Meta Ads management deliverables",subtitle:"Full Facebook and Instagram management. Creative testing is the center of the program. Everything else supports it.",items:[{title:"Account and Pixel Audit",description:"Business Manager review, pixel health check, CAPI setup, and event mapping for accurate tracking."},{title:"Audience Strategy and Build",description:"Custom audiences, lookalikes, interest stacks, and exclusion lists for clean prospecting and retargeting."},{title:"Campaign Structure and Launch",description:"Prospecting, retargeting, and catalog campaigns with proper budget allocation and bid strategies."},{title:"Creative Testing Program",description:"Ad copy, image, and video variations tested on a biweekly cadence with clear kill and scale rules."},{title:"Landing Page and Funnel Alignment",description:"Coordination with your landing pages or ours so ad promise matches the page experience."},{title:"Performance Reporting",description:"Weekly spend, CPM, CTR, CPL, ROAS, and creative performance breakdowns with next-step recommendations."}]},comparison:{title:"Meta Ads: Boost Posts vs. Managed Campaigns",subtitle:"See the difference between DIY boosting and professional Meta Ads management.",layout:"impact",columns:[{header:"Boost Post / DIY"},{header:"KINEXIS Meta Ads",highlight:!0}],rows:[{label:"Targeting precision",values:["Broad, interest-only","Custom audiences, lookalikes, and exclusions"]},{label:"Creative testing",values:["One ad, set and forget","Biweekly creative sprints with 3 to 5 variants"]},{label:"Retargeting funnels",values:["None or basic website visitors","Multi-stage warm and hot retargeting"]},{label:"Tracking accuracy",values:["Pixel only, iOS gaps","Pixel plus Conversions API"]},{label:"Cost per lead",values:["Often 2 to 3x higher","20 to 35% lower after optimization period"]},{label:"Reporting",values:["Platform vanity metrics","CPL, ROAS, and creative-level breakdowns"]}]},extraFaqs:[{question:"How much should I spend on Meta Ads?",answer:"We recommend $3,000 to $15,000 per month in ad spend for most B2B and e-commerce accounts. Below $3,000, the algorithm lacks enough data to optimize effectively. Management fees start at $1,500 per month on top of ad spend."},{question:"Do you create ad creative for Meta campaigns?",answer:"Yes. We write ad copy and coordinate image and video creative as part of the management program. If you need full video production, our video marketing service handles that separately."},{question:"How is Meta Ads management different from PPC management?",answer:"PPC management covers Google, Meta, LinkedIn, and Microsoft as one cross-channel program. Meta Ads management is dedicated to Facebook and Instagram only, with deeper creative testing and audience work specific to the Meta platform."},{question:"How long until Meta Ads become profitable?",answer:"Expect 2 to 4 weeks of creative testing before you find winning ad-audience combinations. Stable ROAS typically arrives between weeks 4 and 8 depending on your offer, creative volume, and monthly spend level."}]},"paid-ads":{metaTitle:"Paid Ads for Lead Generation | KINEXIS Digital",metaDescription:"Paid ads on Google, Meta, and LinkedIn with strategy, landing pages, and tracking tied to qualified leads. Programs from $3,000/mo combined spend and management.",hero:{label:"Paid Ads Services",line1:"Paid media that starts",line2:"with the right channel.",subtitle:"Channel selection, campaign builds, and lead cost tracking for businesses getting serious about paid media. We pick the right platforms for your offer, build campaigns that convert, and measure what actually matters."},answerBlock:"Paid ads services cover channel selection, campaign strategy, ad creation, landing page alignment, conversion tracking, and ongoing optimization across Google, Meta, and LinkedIn. Combined ad spend and management typically starts at $3,000 to $10,000 per month. Most clients see their first qualified leads within 7 to 14 days of launch.",problem:{title:"Most paid ad spend disappears before it reaches sales",intro:"Ads work when channel choice, creative, tracking, and landing pages line up. Most teams jump into one platform with no way to measure what a sales-ready lead costs.",points:["Budget follows the loudest recommendation instead of where buyers actually search or scroll.","Traffic lands on homepage sections never built to convert paid visitors.","Broken or shallow tracking means you optimize toward clicks and form fills, not booked calls.","Campaigns launch with no test plan, so weak ads run for months."]},solution:{title:"Paid ads with a clear line to ROAS",intro:"We match your offer to the right channels, build pages and campaigns for paid traffic, and optimize weekly using lead quality data from your CRM.",points:["Channel picks based on buyer behavior, not platform hype or what worked for someone else's business.","Campaign and landing page builds designed to convert cold traffic from day one.","Tracking that connects ad clicks to CRM leads so cost per acquisition is real.","Structured tests on copy, audiences, and offers with clear scale and kill rules."]},deliverables:{title:"What you get with our paid ads program",subtitle:"Strategy, setup, tracking, and weekly optimization. From channel selection through your first hundred leads.",items:[{title:"Paid Media Strategy and Channel Plan",description:"Platform selection, budget allocation, KPI targets, and competitive analysis before any spend."},{title:"Campaign Build and Launch",description:"Account setup, audience targeting, ad copy, and creative across your chosen platforms."},{title:"Conversion Tracking Implementation",description:"Pixels, tags, GA4 events, and CRM integration so every lead is attributed to its source."},{title:"Landing Page Development or Optimization",description:"Dedicated landing pages built for paid traffic with messaging that matches your ads."},{title:"Weekly Optimization and A/B Testing",description:"Bid adjustments, audience refinements, ad rotation, and budget pacing based on lead data."},{title:"Monthly Performance Review",description:"Spend, CPL, ROAS, and pipeline reporting with recommendations for the next month's budget."}]},comparison:{title:"Getting Started: One Platform vs. Strategic Paid Program",subtitle:"What you gain with a structured paid ads approach instead of ad hoc spending.",layout:"progression",columns:[{header:"Ad Hoc / Single Platform"},{header:"KINEXIS Paid Ads Program",highlight:!0},{header:"Full PPC Management"}],rows:[{label:"Channel strategy",values:["One platform, no comparison","Best-fit channel selection","All channels coordinated"]},{label:"Landing pages",values:["Homepage or generic page","Dedicated conversion pages","Dedicated pages per channel"]},{label:"Tracking setup",values:["Basic pixel or none","Full attribution to CRM","Cross-channel attribution"]},{label:"Optimization",values:["Set and forget","Weekly reviews","Daily cross-channel adjustments"]},{label:"Best for",values:["Testing a small budget","Scaling one proven channel","Multi-channel at $5K+/mo spend"]},{label:"Starting investment",values:["$500 to $1,500/mo","$3,000 to $10,000/mo","$5,000 to $100,000+/mo ad spend"]}]},extraFaqs:[{question:"Which paid ad platform should I start with?",answer:"Depends on your audience. B2B services often start with Google Search. E-commerce often splits between Google Shopping and Meta. Local services do well with Google Search plus Meta retargeting. We recommend the mix on a strategy call."},{question:"How is paid ads different from PPC management?",answer:"Paid ads is for launching or scaling with channel strategy and campaign execution. PPC management is for accounts spending $5,000+ per month across Google, Meta, LinkedIn, and Microsoft with unified optimization."},{question:"What is the minimum budget for paid ads?",answer:"We recommend at least $3,000 per month combined between ad spend and management. Below that, there is rarely enough data to optimize well. Google-only programs can start lower through our Google Ads service."},{question:"Do you build landing pages for paid campaigns?",answer:"Yes. Dedicated landing pages are included or available in most programs. Sending paid traffic to your homepage usually wastes 30 to 50% of budget on visitors who never convert."}]},"web-design":{metaTitle:"Web Design Agency for Lead Generation | KINEXIS Digital",metaDescription:"Custom web design built to convert visitors into leads. Strategy, UX, development, and CRO included. Projects from $8,000 to $35,000, delivered in 6 to 10 weeks.",hero:{label:"Web Design Services",line1:"Websites that look good",line2:"and actually convert.",subtitle:"Built from scratch around how your buyers actually decide. Not a theme with your brand colors swapped in."},answerBlock:"Web design includes discovery, UX strategy, custom design, responsive development, CMS setup, basic SEO structure, and conversion-focused layouts. Projects run $8,000 for focused sites to $35,000+ for larger builds. Typical delivery is 6 to 10 weeks from kickoff to launch.",problem:{title:"Most business websites look fine and convert at 1 to 2%",intro:"A pretty site that does not generate leads is an expense. Templates and DIY builders get you online fast, but they skip the strategy that turns traffic into revenue.",points:["Homepages try to say everything and guide visitors nowhere specific.","Contact forms sit at the bottom of long pages with no reason to fill them out above the fold.","Mobile experience breaks on key pages even though most traffic arrives on a phone.","Slow load times hurt ad quality and SEO while visitors bounce before the page finishes."]},solution:{title:"Websites designed around your sales process",intro:"We map how your buyers decide first, then design pages that move them from awareness to action with clear CTAs, trust signals, and fast load times.",points:["Page architecture based on your services, buyer questions, and conversion goals.","Custom design that reflects your brand without sacrificing speed or usability.","Conversion elements placed where visitors actually decide: above the fold, mid-page, and at exit.","Core Web Vitals optimization so your site performs in search and paid campaigns."]},deliverables:{title:"Web design project deliverables",subtitle:"Discovery through go-live. Every deliverable serves the same goal: qualified visitors who take action.",items:[{title:"Discovery and UX Strategy",description:"Buyer research, sitemap, wireframes, and conversion path mapping before any design work starts."},{title:"Custom Visual Design",description:"Brand-aligned mockups for key pages with mobile and desktop layouts, no templates."},{title:"Responsive Development",description:"Clean, fast code on modern frameworks with CMS integration for easy content updates."},{title:"Conversion-Focused Page Templates",description:"Service pages, landing pages, and contact flows built with forms, CTAs, and trust signals."},{title:"On-Page SEO Foundation",description:"Title tags, meta descriptions, schema markup, and site structure ready for organic growth."},{title:"Launch Support and Training",description:"QA testing, analytics setup, CMS training, and 30 days of post-launch adjustments."}]},comparison:{title:"Custom Web Design vs. Template Builders",subtitle:"Compare a conversion-focused custom build against DIY and template options.",layout:"contrast",columns:[{header:"Template / DIY Builder"},{header:"KINEXIS Web Design",highlight:!0}],rows:[{label:"Strategy and UX",values:["Pick a theme, add text","Discovery, wireframes, and conversion mapping"]},{label:"Page speed",values:["Bloated themes, slow loads","Optimized for Core Web Vitals"]},{label:"Conversion design",values:["Generic layouts","CTAs and forms placed by intent"]},{label:"SEO readiness",values:["Basic, plugin-dependent","Built-in structure and schema"]},{label:"Project cost",values:["$500 to $3,000","$8,000 to $35,000"]},{label:"Typical conversion lift",values:["Baseline","25 to 60% increase with paired CRO"]}]},extraFaqs:[{question:"How much does a custom website cost?",answer:"Most business websites range from $8,000 to $35,000 depending on page count, custom functionality, and integrations. E-commerce and multi-location sites may exceed that range. We provide a fixed quote after discovery."},{question:"How long does a web design project take?",answer:"Standard business websites take 6 to 10 weeks from kickoff to launch. Larger sites with custom features may take 10 to 14 weeks. We set a clear timeline in your proposal with milestone check-ins."},{question:"Do you redesign existing websites or only build new ones?",answer:"Both. We redesign underperforming sites and build new ones from scratch. Redesigns often include a conversion audit first so we fix what is broken before changing the design."},{question:"What CMS do you build on?",answer:"We primarily build on Next.js and headless CMS platforms for speed and flexibility. For clients who need WordPress, we build custom themes without page builder bloat."}]},cro:{metaTitle:"Conversion Rate Optimization (CRO) | KINEXIS Digital",metaDescription:"CRO that turns more of your existing traffic into leads and sales. Audits, A/B tests, and UX fixes with measurable lift. From $2,500/mo or project-based.",hero:{label:"Conversion Rate Optimization",line1:"More leads from",line2:"traffic you already have.",subtitle:"CRO is the only channel that makes every other channel more efficient. We audit where visitors drop off, build hypothesis-driven tests, and compound the lift month over month."},answerBlock:"CRO services include conversion audits, heatmap and session analysis, hypothesis development, A/B testing, and UX improvements on high-traffic pages. Retainers start at $2,500 per month or project-based for single-page optimization. Most tests reach statistical significance within 2 to 4 weeks.",problem:{title:"Buying more traffic rarely fixes a leaky site",intro:"If two out of a hundred visitors convert, doubling ad spend just doubles the waste. Most teams chase volume while the pages that should close the deal stay untested.",points:["Landing pages bury the offer and hide the next step below the fold.","Forms ask for everything upfront, so people leave halfway through.","Mobile layouts break on the pages where most of your traffic arrives.","Changes happen by gut feel because nobody set up a testing rhythm."]},solution:{title:"Testing that stacks small wins into big lift",intro:"We start with your highest-traffic pages, find the biggest leaks, and run structured tests you can roll out site-wide once they win.",points:["Audits backed by analytics, heatmaps, and session recordings on pages that matter most.","Hypothesis-driven A/B tests on headlines, CTAs, form fields, and layout.","UX fixes for mobile, speed, and navigation before you spend weeks testing broken basics.","Reporting on conversion lift, incremental leads, and revenue tied to each test."]},deliverables:{title:"What you get with our CRO program",subtitle:"Audit, hypotheses, structured tests, and implementation. Each round builds on the last.",items:[{title:"Conversion Audit and Opportunity Map",description:"Analytics review, funnel analysis, heatmaps, and session recordings with prioritized fix list."},{title:"Hypothesis Development",description:"Data-backed test ideas ranked by expected impact and implementation effort."},{title:"A/B and Multivariate Testing",description:"Structured experiments on headlines, CTAs, forms, layouts, and social proof elements."},{title:"UX and Copy Improvements",description:"Page-level copy, design, and layout changes based on audit findings and test results."},{title:"Form and CTA Optimization",description:"Field reduction, multi-step forms, button copy, and placement testing on key pages."},{title:"Monthly Lift Reporting",description:"Test results, conversion rate changes, incremental leads, and rollout recommendations."}]},comparison:{title:"CRO: More Traffic vs. Better Conversion",subtitle:"See why optimizing existing traffic often beats buying more of it.",layout:"impact",columns:[{header:"Increase Ad Spend 50%"},{header:"KINEXIS CRO Program",highlight:!0}],rows:[{label:"Cost to add 50% more leads",values:["50% higher ad budget","$2,500/mo retainer, same ad spend"]},{label:"Timeline",values:["Immediate but expensive","2 to 8 weeks for test results"]},{label:"Compounding effect",values:["Stops when budget stops","Lift applies to all traffic sources"]},{label:"Risk",values:["Higher CPL if landing pages stay weak","Low risk, data-driven changes"]},{label:"Typical conversion lift",values:["0% if pages are the bottleneck","15 to 45% on optimized pages"]},{label:"Works with SEO traffic",values:["N/A","Yes, lift applies to organic and paid"]}]},extraFaqs:[{question:"How much traffic do I need for CRO testing?",answer:"About 1,000 monthly sessions on the pages you test is enough to reach significance in 2 to 4 weeks. Lower-traffic pages can still gain from audit-driven UX fixes without formal A/B tests."},{question:"What conversion rate improvement should I expect?",answer:"Many clients see 15 to 45% lift on optimized pages within the first 90 days. Starting point and industry matter. Sites with obvious friction often see the biggest early jumps."},{question:"How is CRO different from web design?",answer:"Web design builds or rebuilds the site. CRO improves what you already have through testing and UX work on traffic you are paying for or earning today. A lot of clients do both."},{question:"Do you run CRO on landing pages used for paid ads?",answer:"Yes. Paid landing pages are often first in line because even a small lift directly lowers cost per lead and improves ROAS."}]},"email-marketing":{metaTitle:"Email Marketing & Automation for B2B | KINEXIS Digital",metaDescription:"Email sequences and campaigns that nurture leads into customers. Automation, segmentation, and deliverability tied to pipeline. From $2,000/mo.",hero:{label:"Email Marketing Services",line1:"Email that moves",line2:"prospects toward a yes.",subtitle:"Automated sequences segmented by behavior and pipeline stage, not broadcast calendar. From first opt-in through post-sale retention, built to move people, not fill inboxes."},answerBlock:"Email marketing services include list strategy, automation workflows, campaign creation, segmentation, A/B testing, and deliverability monitoring. Retainers start at $2,000 to $5,000 per month depending on list size and automation complexity. Welcome sequences typically launch within 2 to 3 weeks.",problem:{title:"Opens look fine. Pipeline does not move.",intro:"Collecting emails is easy. Turning them into booked calls takes sequences built around how your buyers actually decide, not a broadcast calendar.",points:["Monthly newsletters go out with no tie to where each subscriber is in the buying process.","Automation stops after welcome email one instead of nurturing over weeks.","Everyone gets the same message because lists were never segmented by interest or behavior.","Deliverability slips because lists were never cleaned or domains never warmed properly."]},solution:{title:"Automation mapped to your sales cycle",intro:"Segmented sequences that send the right message at the right time, from first opt-in through post-purchase follow-up.",points:["Welcome, nurture, and re-engagement flows tied to specific offers and buyer stages.","Segments by lead source, behavior, and engagement so copy stays relevant.","Tests on subject lines, send times, and CTAs to improve opens and clicks over time.","Deliverability setup: SPF, DKIM, DMARC, and list hygiene to protect inbox placement."]},deliverables:{title:"What you get with email marketing",subtitle:"Everything from list strategy and automation builds to campaign copy and deliverability monitoring.",items:[{title:"Email Strategy and Calendar",description:"Segmentation plan, send frequency, campaign themes, and automation map aligned to your funnel."},{title:"Automation Workflow Build",description:"Welcome series, nurture sequences, abandoned lead follow-ups, and post-sale retention flows."},{title:"Campaign Copy and Design",description:"Email copy, subject lines, and mobile-responsive templates for broadcasts and automations."},{title:"List Segmentation and Management",description:"Tags, segments, and suppression rules based on behavior, source, and engagement level."},{title:"A/B Testing Program",description:"Structured tests on subject lines, preview text, CTAs, and send times with documented results."},{title:"Performance and Deliverability Reporting",description:"Open rates, click rates, conversions, unsubscribes, and inbox placement monitoring monthly."}]},comparison:{title:"Email Marketing: DIY Platform vs. Managed Program",subtitle:"What you get with a managed email program versus running it yourself.",layout:"stacked",columns:[{header:"DIY on Mailchimp / HubSpot"},{header:"KINEXIS Email Marketing",highlight:!0}],rows:[{label:"Strategy",values:["Ad hoc broadcasts","Funnel-mapped automation plan"]},{label:"Copy and design",values:["Internal team or templates","Professional copy and custom templates"]},{label:"Segmentation",values:["Basic lists","Behavior and source-based segments"]},{label:"Testing",values:["Rare or none","Ongoing A/B testing program"]},{label:"Deliverability",values:["Often neglected","Active monitoring and list hygiene"]},{label:"Time investment",values:["5 to 10 hours/week internally","Fully managed execution"]}]},extraFaqs:[{question:"Which email platforms do you work with?",answer:"HubSpot, ActiveCampaign, Klaviyo, Mailchimp, and ConvertKit depending on your business and integrations. We recommend the best fit on a strategy call."},{question:"How much does email marketing management cost?",answer:"Retainers run $2,000 to $5,000 per month based on list size, number of automations, and send frequency. New automation builds sometimes include a one-time onboarding fee."},{question:"How quickly can you launch email automations?",answer:"Welcome and basic nurture sequences usually go live in 2 to 3 weeks. Full funnel automation with segmentation and multiple flows takes 4 to 6 weeks."},{question:"Can you improve our email deliverability?",answer:"Yes. We audit SPF, DKIM, and DMARC, clean your list, warm new domains properly, and watch spam complaint rates. Most issues clear within 2 to 4 weeks of fixes."}]},"content-marketing":{metaTitle:"Content Marketing for B2B Pipeline | KINEXIS Digital",metaDescription:"Content that ranks in search and earns buyer trust. Strategy, blog posts, guides, and distribution from $2,500/mo. First pieces live in 3 to 4 weeks.",hero:{label:"Content Marketing Services",line1:"Content that answers",line2:"what buyers search before they call.",subtitle:"Content that earns rankings, builds credibility with buyers who aren't ready yet, and links naturally to the pages where you close. Written to a brief, not a word count target."},answerBlock:"Content marketing services include content strategy, keyword-driven topic planning, blog posts, guides, case studies, and distribution across search and social. Retainers start at $2,500 to $6,000 per month for 4 to 8 pieces monthly. First published content typically goes live within 3 to 4 weeks of kickoff.",problem:{title:"Publishing without a plan creates noise, not pipeline",intro:"Random blog posts do not build authority. Content only pays off when it targets the questions your buyers ask right before they contact you or a competitor.",points:["Topics get picked in meetings instead of from keyword intent and buyer stage.","Posts read like filler with no original insight, data, or proof.","Articles go live once and never get promoted, linked internally, or refreshed.","No line connects content topics to the service pages and offers that actually sell."]},solution:{title:"Content that ranks, teaches, and sends people to your offer",intro:"We plan around the keywords and questions your buyers search, then write pieces that build trust and link naturally to pages where you close.",points:["Topic clusters organized around core services and the questions buyers ask at each stage.","SEO-informed writing with real examples, client stories, and actionable takeaways.","Internal linking that passes authority to your money pages.","Refresh cycles that update winners and retire posts that never earned traffic."]},deliverables:{title:"What you get with content marketing",subtitle:"Strategy, production, and distribution. Not just articles. A content engine mapped to your sales funnel.",items:[{title:"Content Strategy and Editorial Calendar",description:"Topic clusters, keyword targets, publishing schedule, and content types mapped to your funnel."},{title:"Blog Posts and Articles",description:"1,500 to 2,500 word SEO-informed posts with original angles, data, and internal links."},{title:"Guides and Lead Magnets",description:"Downloadable resources designed to capture emails and position your brand as the expert."},{title:"Case Studies and Social Proof Content",description:"Client success stories formatted for your website, sales team, and email nurture sequences."},{title:"Content Distribution Plan",description:"Social sharing, email promotion, and outreach to amplify each piece beyond organic search."},{title:"Performance Reporting",description:"Traffic, rankings, engagement, and lead attribution by content piece monthly."}]},comparison:{title:"Content Marketing: Freelancer vs. Agency Program",subtitle:"Compare hiring a freelance writer against a full content marketing program.",layout:"stacked",columns:[{header:"Freelance Writer"},{header:"KINEXIS Content Marketing",highlight:!0}],rows:[{label:"Strategy",values:["You provide topics","Keyword and funnel-mapped editorial plan"]},{label:"SEO integration",values:["Basic or none","Built into every piece from planning to publishing"]},{label:"Content types",values:["Blog posts only","Posts, guides, case studies, and lead magnets"]},{label:"Internal linking",values:["Not included","Authority flow to service and landing pages"]},{label:"Distribution",values:["Publish and hope","Promotion across search, email, and social"]},{label:"Monthly investment",values:["$500 to $1,500 per piece","$2,500 to $6,000 for 4 to 8 pieces"]}]},extraFaqs:[{question:"How many content pieces do you produce per month?",answer:"Most retainers include 4 to 8 pieces per month depending on length and type. A typical mix is 3 to 4 blog posts plus one guide or case study. Volume adjusts to your goals and budget."},{question:"Do you write content for SEO purposes?",answer:"Yes. Every piece starts with keyword research and search intent. Content marketing and SEO overlap in our programs. Dedicated SEO adds technical work and link building on top."},{question:"How long until content marketing drives traffic?",answer:"New posts often start ranking in 60 to 90 days. Compound traffic builds over 6 to 12 months as your library grows. Lead magnets can pull emails immediately when promoted."},{question:"Can you write content for my specific industry?",answer:"Yes. We work across home services, healthcare, professional services, SaaS, and e-commerce. We research your market, talk to your team, and use client examples so it reads like insider knowledge."}]},"social-media":{metaTitle:"Social Media Management for B2B Brands | KINEXIS Digital",metaDescription:"Social media that builds visibility and sends people to your site. Content, posting, and community management from $1,500/mo.",hero:{label:"Social Media Marketing",line1:"Social that supports",line2:"the rest of your marketing.",subtitle:"Consistent, on-brand presence that keeps you visible to buyers who haven't decided yet and sends them somewhere useful when they are."},answerBlock:"Social media marketing includes platform strategy, content creation, posting schedules, community management, and performance reporting for LinkedIn, Instagram, Facebook, and X. Management starts at $1,500 to $4,000 per month depending on platforms and posting frequency. Content calendars are live within 2 weeks of kickoff.",problem:{title:"An inactive profile hurts trust faster than no profile at all",intro:"Posting when someone remembers, with no clear voice or goal, makes you look smaller than you are. Social only helps when it connects to traffic, offers, and leads.",points:["Promotional posts go out sporadically and get ignored.","No content pillars or voice guidelines, so every post feels like a different company.","Likes and follows get tracked while website clicks and leads do not.","Comments and DMs sit unanswered for days, which signals you are not paying attention."]},solution:{title:"Social tied to revenue goals, not vanity metrics",intro:"A content system with clear pillars, a steady posting rhythm, and CTAs that send followers to your site, offers, and lead magnets.",points:["Platform focus on where your buyers actually spend time, not every network at once.","Content pillars aligned with your services, expertise, and the questions buyers ask.","Steady posting with graphics, captions, and hashtags tuned per platform.","Community replies on comments and DMs within 24 hours."]},deliverables:{title:"What you get with social media management",subtitle:"Content, scheduling, community management, and traffic CTAs. All managed.",items:[{title:"Platform Strategy and Content Pillars",description:"Channel selection, posting frequency, content themes, and brand voice guidelines."},{title:"Content Creation and Design",description:"Graphics, carousels, short-form copy, and video snippets tailored to each platform."},{title:"Scheduling and Publishing",description:"Consistent posting calendar with optimal send times and platform-specific formatting."},{title:"Community Management",description:"Comment responses, DM handling, and engagement with relevant accounts in your space."},{title:"Social-to-Website CTAs",description:"Bio links, story CTAs, and post copy that drive traffic to landing pages and offers."},{title:"Monthly Analytics Report",description:"Follower growth, reach, engagement, click-throughs, and top-performing content breakdown."}]},comparison:{title:"Social Media: In-House vs. Managed",subtitle:"Compare hiring internally against a managed social media program.",layout:"ledger",columns:[{header:"In-House Social Manager"},{header:"KINEXIS Social Media",highlight:!0}],rows:[{label:"Monthly cost",values:["$4,000 to $6,000 salary plus tools","$1,500 to $4,000 all-in"]},{label:"Content volume",values:["Limited by one person","Design, copy, and scheduling team"]},{label:"Platform coverage",values:["1 to 2 platforms well","Multi-platform with platform-specific content"]},{label:"Strategy",values:["Often reactive posting","Content pillars tied to business goals"]},{label:"Community management",values:["Business hours only","Daily monitoring and response"]},{label:"Time to launch",values:["30 to 60 days to hire","2 weeks to live content calendar"]}]},extraFaqs:[{question:"Which social media platforms do you manage?",answer:"LinkedIn, Instagram, Facebook, and X. We usually recommend 2 to 3 platforms where your buyers are active instead of spreading thin everywhere."},{question:"How is social media management different from Meta Ads?",answer:"Social management is organic content, posting, and community work. Meta Ads is paid Facebook and Instagram advertising. They work well together but play different roles."},{question:"Do you create graphics and videos for social posts?",answer:"Yes. Graphics, carousels, and short video clips are included in management packages. Long-form video production goes through our video marketing service."},{question:"Can social media actually generate leads for B2B?",answer:"Social is rarely a direct lead channel for B2B, but it builds trust and sends people to your content, offers, and site. We track click-throughs and attribute leads that started from social touchpoints."}]},"video-marketing":{metaTitle:"Video Marketing for Ads, Social & Web | KINEXIS Digital",metaDescription:"Video for ads, social, and website conversion. Scripting, production, and editing from $3,000 per project or $2,500/mo retainer.",hero:{label:"Video Marketing Services",line1:"Video built for",line2:"where it actually runs.",subtitle:"Script, shoot, edit, distribute. Short-form for ads and social. Long-form for your site and email. Each piece built around one clear message, formatted for the channel where it runs."},answerBlock:"Video marketing services include concept development, scripting, production coordination, editing, and distribution planning for ads, social, and web. Project pricing starts at $3,000 for short-form packages. Monthly retainers from $2,500 cover ongoing video content. Typical turnaround is 2 to 4 weeks per project.",problem:{title:"Most business video tries to say everything at once",intro:"Video wins attention on every platform, but long, unfocused pieces hurt brand perception and ad performance. Without a distribution plan, content sits on YouTube while creative goes stale.",points:["One video attempts to cover the whole company instead of making a single point.","Quality swings from shoot to shoot, which makes ads and social feel disconnected.","Finished files never get cut for ads, email, or the homepage.","New ad creative is slow or expensive, so campaigns fatigue in a few weeks."]},solution:{title:"One message per video, sized for the channel",intro:"We script and produce for where each piece will live: a 15-second ad, a 60-second social clip, or a three-minute explainer on your site.",points:["Formats matched to platform: vertical for social, horizontal for YouTube, short cuts for ads.","Scripts built around one takeaway and a clear CTA at the end.","Production workflows that yield multiple cuts from a single shoot.","Distribution planning so video reaches ads, social, email, and your website."]},deliverables:{title:"What you get with video marketing",subtitle:"Concept, scripting, production, editing, and multi-format exports for every channel you run.",items:[{title:"Video Strategy and Content Plan",description:"Video types, platform mapping, messaging themes, and production calendar."},{title:"Scriptwriting and Storyboarding",description:"Scripts, shot lists, and storyboards approved before production begins."},{title:"Production Coordination",description:"On-location or remote recording with professional lighting, audio, and direction."},{title:"Editing and Post-Production",description:"Cuts, captions, graphics, music licensing, and color grading for polished final files."},{title:"Platform-Optimized Exports",description:"Multiple aspect ratios and lengths formatted for ads, social, web, and email."},{title:"Performance Tracking Setup",description:"View counts, engagement, click-throughs, and ad performance tied to each video asset."}]},comparison:{title:"Video Marketing: One-Off vs. Ongoing Program",subtitle:"Compare a single video project against a monthly video content program.",layout:"stacked",columns:[{header:"One-Off Explainer Video"},{header:"KINEXIS Video Retainer",highlight:!0}],rows:[{label:"Investment",values:["$5,000 to $15,000 once","$2,500 to $6,000/mo ongoing"]},{label:"Content volume",values:["1 video","4 to 8 pieces per month"]},{label:"Ad creative refresh",values:["Stale after 4 to 6 weeks","New ad cuts every month"]},{label:"Platform coverage",values:["One format","Multi-format exports per shoot"]},{label:"Turnaround",values:["6 to 8 weeks","2 to 4 weeks per batch"]},{label:"Best for",values:["Website hero video","Active ad and social programs"]}]},extraFaqs:[{question:"How much does video production cost?",answer:"Short-form social packages start at $3,000 per project. Explainers run $5,000 to $12,000. Monthly retainers from $2,500 deliver 4 to 8 pieces. We quote on length, complexity, and number of deliverables."},{question:"Do I need to be on camera?",answer:"Not necessarily. We produce founder-led, team interview, animation, and b-roll style depending on your brand. On camera builds trust fastest for many service businesses, but it is optional."},{question:"Can you create video ads for Meta and Google?",answer:"Yes. We deliver ad-specific cuts in the formats and lengths each platform requires. This pairs with our Meta Ads and Google Ads management."},{question:"How long does video production take?",answer:"Most projects deliver in 2 to 4 weeks from script approval to final files. Retainer clients get a rolling calendar with new content every month."}]},branding:{metaTitle:"Branding & Identity for B2B Companies | KINEXIS Digital",metaDescription:"Brand positioning, visual identity, and messaging for B2B companies. Strategy and design packages from $8,000 to $25,000.",hero:{label:"Branding Services",line1:"A brand buyers recognize",line2:"before they read fine print.",subtitle:"Brand strategy, visual identity, and messaging guidelines. Built once, referenced everywhere so your ads, your site, and your proposals all sound like the same company made them."},answerBlock:"Branding services include market positioning, brand strategy, logo design, visual identity systems, messaging frameworks, and brand guidelines. Projects range from $8,000 for focused identity refreshes to $25,000+ for full brand strategy and design. Typical delivery is 6 to 10 weeks.",problem:{title:"Inconsistent branding makes you look smaller than you are",intro:"When logo, colors, and message shift from website to ads to proposals, buyers pick whoever looks more put together. Brand work is not decoration. It is what every other channel builds on.",points:["Visuals vary across website, ads, and social so nothing feels like one company.","Messaging tries to speak to everyone and lands with no one in particular.","No brand guidelines, so every new asset looks like a one-off.","Positioning stays vague, so prospects cannot explain why they should choose you."]},solution:{title:"Brand strategy that makes marketing easier to run",intro:"We clarify who you serve, what makes you different, and how you look and sound, then document it so your team and partners stay aligned.",points:["Positioning workshops on ideal customer, differentiators, and competitive angle.","Visual identity: logo, color palette, typography, and design system.","Messaging framework with taglines, value props, and tone of voice.","Brand guidelines your team and agencies reference for every new asset."]},deliverables:{title:"What you get with a branding project",subtitle:"Strategy, identity, messaging, and guidelines your team can actually use.",items:[{title:"Brand Strategy and Positioning",description:"Market analysis, competitor review, ideal customer profile, and positioning statement."},{title:"Logo and Visual Identity Design",description:"Primary and secondary logos, color palette, typography, and icon style."},{title:"Messaging Framework",description:"Tagline, elevator pitch, value propositions, and tone of voice guidelines."},{title:"Brand Guidelines Document",description:"Usage rules for logo, colors, fonts, imagery, and messaging across all channels."},{title:"Business Collateral Templates",description:"Presentation decks, proposal templates, social profile assets, and email signatures."},{title:"Brand Launch Support",description:"Rollout plan for updating your website, social profiles, and marketing materials."}]},comparison:{title:"Branding: Fiverr Logo vs. Full Brand Strategy",subtitle:"What you get with a strategic branding project versus a logo-only purchase.",layout:"contrast",columns:[{header:"Logo-Only Service"},{header:"KINEXIS Branding",highlight:!0}],rows:[{label:"Strategy",values:["None","Positioning, messaging, and competitive analysis"]},{label:"Deliverables",values:["One logo file","Full identity system and guidelines"]},{label:"Messaging",values:["Not included","Tagline, value props, and tone of voice"]},{label:"Consistency",values:["No usage rules","Documented guidelines for all channels"]},{label:"Investment",values:["$50 to $500","$8,000 to $25,000"]},{label:"Marketing impact",values:["Cosmetic change","Foundation for all marketing channels"]}]},extraFaqs:[{question:"How much does a branding project cost?",answer:"Identity refreshes start at $8,000. Full strategy with positioning, messaging, and visual identity runs $15,000 to $25,000. We scope deliverables and timeline in discovery."},{question:"How long does branding take?",answer:"Most projects finish in 6 to 10 weeks. Strategy and positioning take 2 to 3 weeks, design exploration 3 to 4 weeks, guidelines and collateral 1 to 2 weeks."},{question:"Do I need branding before I start marketing?",answer:"You can market without a full rebrand, but clear positioning and consistent visuals make every channel work harder. We often run branding and web design in parallel."},{question:"Will I own all brand files and fonts?",answer:"Yes. You get logo files, design assets, font licenses, and the guidelines document. Everything is yours to use internally and with any partner."}]},analytics:{metaTitle:"Marketing Analytics & Revenue Reporting | KINEXIS Digital",metaDescription:"Marketing analytics that connects campaigns to revenue. GA4 setup, dashboards, and attribution from $1,500/mo.",hero:{label:"Marketing Analytics Services",line1:"Reports that tell you",line2:"where to spend next.",subtitle:"Marketing analytics that connects ad spend to pipeline. We fix the tracking, build dashboards around the numbers that matter, and report on what you should actually do next."},answerBlock:"Marketing analytics services include GA4 setup, conversion tracking, CRM integration, custom dashboards, and monthly reporting across SEO, paid ads, email, and social. Retainers start at $1,500 to $3,500 per month. Dashboard builds typically go live within 2 to 3 weeks.",problem:{title:"Dashboards full of traffic rarely help you allocate budget",intro:"Impressions and page views look busy but say little about whether marketing is producing revenue. Bad tracking leads to bad spend decisions.",points:["GA4 is installed but events, conversions, and audiences are wrong or missing.","Ad platform numbers never connect to CRM leads, so true ROAS stays unknown.","Reports show channel traffic without tying visits to qualified leads or closed deals.","Different people pull from different tools and walk away with different conclusions."]},solution:{title:"Analytics wired to business outcomes",intro:"We fix the tracking foundation, build dashboards around metrics you act on, and report monthly on what to keep, cut, or scale.",points:["GA4 and tag manager setup with proper events, conversions, and audiences.","CRM and ad platform integration so leads trace back to channel and campaign.","Custom dashboards in GA4, Looker Studio, or your preferred tool focused on KPIs that matter.","Monthly reporting with recommendations, not screenshot dumps."]},deliverables:{title:"What you get with marketing analytics",subtitle:"Foundation, dashboards, and monthly reporting tied to the decisions that move your budget.",items:[{title:"Analytics Audit and Fix Plan",description:"Review of GA4, tags, pixels, CRM integration, and conversion definitions with prioritized fixes."},{title:"GA4 and Tag Manager Setup",description:"Event tracking, conversion actions, enhanced measurement, and cross-domain configuration."},{title:"CRM and Ad Platform Integration",description:"Lead source attribution connecting HubSpot, Salesforce, or your CRM to ad and organic data."},{title:"Custom Dashboard Build",description:"Looker Studio or GA4 dashboards showing traffic, leads, CPL, ROAS, and pipeline by channel."},{title:"Monthly Performance Report",description:"Channel-by-channel breakdown with trends, anomalies, and actionable recommendations."},{title:"Quarterly Strategy Review",description:"Deep dive into attribution data with budget reallocation recommendations for the next quarter."}]},comparison:{title:"Marketing Analytics: Default GA4 vs. Managed Program",subtitle:"What changes when analytics is set up and managed by specialists.",layout:"ledger",columns:[{header:"Default GA4 / DIY Setup"},{header:"KINEXIS Analytics",highlight:!0}],rows:[{label:"Conversion tracking",values:["Page views and basic events","Qualified lead and revenue events"]},{label:"CRM integration",values:["Manual or none","Automated source attribution"]},{label:"Dashboards",values:["Generic GA4 reports","Custom KPI dashboards"]},{label:"Cross-channel view",values:["Siloed platform data","Unified channel performance view"]},{label:"Reporting cadence",values:["Ad hoc when someone asks","Monthly with recommendations"]},{label:"Decision quality",values:["Guesswork on budget allocation","Data-backed channel investment"]}]},extraFaqs:[{question:"Which analytics tools do you work with?",answer:"GA4, Google Tag Manager, Looker Studio, HubSpot, Salesforce, and native ad platform analytics. We build in whatever your team already uses or recommend a fit."},{question:"How much does marketing analytics management cost?",answer:"Retainers run $1,500 to $3,500 per month depending on channels, integrations, and reporting depth. One-time GA4 and dashboard setup projects start at $3,000."},{question:"Can you fix our existing GA4 setup?",answer:"Yes. Most audits we run find missing events, duplicate conversions, or broken CRM connections. Core tracking issues usually clear in 2 to 3 weeks."},{question:"Do you report on ROI and ROAS?",answer:"Yes, when CRM integration is in place. We report cost per lead, cost per acquisition, ROAS by channel, and pipeline value tied to marketing."}]},"growth-consulting":{metaTitle:"Growth Consulting & Marketing Strategy | KINEXIS Digital",metaDescription:"Marketing strategy before execution. Channel audits, roadmaps, and quarterly planning from $3,000/mo for businesses that need a plan first.",hero:{label:"Growth Consulting Services",line1:"Know what to do",line2:"before you spend again.",subtitle:"A strategy engagement for businesses that know they need to grow but aren't sure where to invest next. We audit what you have, map the gaps, and deliver a channel plan with realistic budgets and timelines."},answerBlock:"Growth consulting includes marketing audits, competitive analysis, channel strategy, budget planning, and quarterly roadmaps. Engagements start at $3,000 to $6,000 per month for advisory or $5,000 to $15,000 for project-based strategy deliverables. Initial audit and roadmap delivery takes 3 to 4 weeks.",problem:{title:"Tactics without strategy burn budget fast",intro:"Most owners know they need marketing but lack a clear plan for which channels to prioritize, how much to invest, and what results to expect in 90 days.",points:["Budget gets split across too many channels so none get enough to work.","Past agency relationships ended with no documented learnings or strategy.","Internal teams execute tasks while nobody owns the overall growth plan.","Revenue targets get set without a marketing plan that can realistically support them."]},solution:{title:"A growth roadmap built on your data and market",intro:"We audit what you have, study your competitive landscape, and deliver a prioritized plan with channel picks, budget splits, and KPI targets.",points:["Marketing audit across website, ads, SEO, email, and analytics.","Competitive review of where rivals invest and where gaps exist in your market.","Channel strategy with investment levels and realistic timelines per channel.","Quarterly roadmap with milestones, KPIs, and decision points for scaling or pivoting."]},deliverables:{title:"What you get with growth consulting",subtitle:"Audit, competitive analysis, channel plan, roadmap, and quarterly reviews. Your team executes with clarity.",items:[{title:"Marketing Audit and Scorecard",description:"Assessment of every active channel with scores for tracking, creative, targeting, and conversion."},{title:"Competitive Market Analysis",description:"Review of competitor positioning, ad spend signals, content strategy, and keyword gaps."},{title:"Channel Strategy and Budget Plan",description:"Recommended channel mix, monthly budget allocation, and expected CPL and timeline by channel."},{title:"Growth Roadmap Document",description:"Quarterly plan with priorities, milestones, KPIs, and dependencies between channels."},{title:"Quarterly Strategy Sessions",description:"Live working sessions to review performance, adjust priorities, and plan the next quarter."},{title:"Execution Handoff or Managed Rollout",description:"Option to execute the plan with our team or hand off to your internal team with clear specs."}]},comparison:{title:"Growth Consulting vs. Jumping Into Execution",subtitle:"Why strategy before tactics saves budget and accelerates results.",layout:"stacked",columns:[{header:"Start Running Ads Immediately"},{header:"KINEXIS Growth Consulting",highlight:!0}],rows:[{label:"Upfront investment",values:["$0 strategy, $5K+/mo in ads","$3K to $6K/mo advisory"]},{label:"Channel selection",values:["Guess or copy competitors","Data-backed recommendation"]},{label:"Budget efficiency",values:["30 to 50% wasted in first 90 days","Prioritized spend from day one"]},{label:"Tracking readiness",values:["Fixed after problems appear","Built into the plan before launch"]},{label:"Timeline to results",values:["Unpredictable","Realistic milestones by channel"]},{label:"Best for",values:["Proven offer, ready to scale","Unclear strategy or past failures"]}]},extraFaqs:[{question:"How is growth consulting different from your other services?",answer:"Growth consulting is strategy and planning. Our other services are execution. Many clients start here to build the roadmap, then engage us or their internal team for SEO, ads, web design, and other channels."},{question:"Do you execute the strategy or just advise?",answer:"Both. Advisory engagements give your team the plan and quarterly guidance. Managed engagements add our execution team running the channels in the roadmap."},{question:"How much does growth consulting cost?",answer:"Advisory retainers run $3,000 to $6,000 per month. Project-based strategy deliverables range from $5,000 to $15,000 for the audit, competitive analysis, and roadmap document."},{question:"How long does a growth consulting engagement last?",answer:"Most advisory clients work with us 3 to 6 months to build and refine the plan, then move to execution. Some keep us on quarterly for strategic oversight."}]},funnels:{metaTitle:"Funnels & CRO for Lead Conversion | KINEXIS Digital",metaDescription:"Funnels and conversion optimization in one system. Landing pages, email automation, A/B testing, and UX fixes. Projects from $5,000; programs from $2,500/mo.",hero:{label:"Funnels & Conversion Rate Optimization",line1:"Capture and nurture leads",line2:"then keep testing what converts.",subtitle:"The full conversion path: opt-in pages, lead magnets, email nurture, retargeting, and A/B testing. Built and kept under test as one connected system from first click to booked call."},answerBlock:"Funnels & CRO services include funnel strategy, landing page design, lead magnet creation, email automation, retargeting, heatmap analysis, and structured A/B testing. Funnel builds start at $5,000 to $15,000; ongoing CRO programs from $2,500 per month. Most systems launch in 4 to 8 weeks with optimization continuing after go-live.",problem:{title:"A landing page is not a funnel",intro:"Traffic without follow-up and testing is expensive waste. Most businesses lose leads between form fill and booking, and never run the tests that would show them why.",points:["Leads opt in and hear nothing beyond a generic thank-you page.","Landing pages convert at 1 to 2% because the message does not match the ad or offer.","Changes happen by guesswork because no one set up a testing framework.","Retargeting and nurture stop early, so unconverted visitors disappear."]},solution:{title:"One system: capture, nurture, test, convert",intro:"We build the full path and keep improving it: opt-in pages, lead magnets, email automation, retargeting, heatmaps, and A/B tests that compound lift over time.",points:["Funnel architecture mapped to your offer, audience, and sales cycle length.","Landing pages with lead magnets and thank-you flows that qualify intent.","Multi-step email and SMS sequences with behavioral triggers and booking CTAs.","CRO program with heatmaps, session recordings, and statistically valid A/B tests."]},deliverables:{title:"What you get with funnels and CRO",subtitle:"Every stage of the conversion path. Built, connected, and kept under test until the numbers move.",items:[{title:"Funnel Strategy and Architecture",description:"Funnel map, offer positioning, audience targeting, and conversion path from ad click to sale."},{title:"Landing Pages and Lead Magnets",description:"Opt-in page design, lead magnet creation, thank-you pages, and CRO-ready copy and structure."},{title:"Email and SMS Automation",description:"5 to 10 step nurture sequences with segmentation, triggers, and booking or purchase CTAs."},{title:"Conversion Audit and Heatmap Analysis",description:"Analytics review, funnel drop-off analysis, heatmaps, and session recordings with prioritized fix list."},{title:"A/B and Multivariate Testing",description:"Hypothesis-driven experiments on headlines, CTAs, forms, layouts, and offers with significance gates."},{title:"Retargeting, CRM Integration, and Tracking",description:"Pixel audiences, form-to-CRM routing, and end-to-end conversion tracking at every funnel stage."}]},comparison:{title:"Landing Page Only vs. Full Funnel + CRO System",subtitle:"What you gain when build and optimization work as one program.",layout:"impact",columns:[{header:"Landing Page Only"},{header:"KINEXIS Funnels & CRO",highlight:!0}],rows:[{label:"Lead capture",values:["Single opt-in point","Multiple entry points and offers"]},{label:"Follow-up",values:["Thank-you page, nothing else","5 to 10 email nurture sequence"]},{label:"Optimization",values:["Launch and forget","Ongoing A/B tests and UX improvements"]},{label:"Conversion rate",values:["1 to 3% opt-in typical","3 to 8% with optimized funnel + testing"]},{label:"Compounding lift",values:["Stops after launch","15 to 45% lift per winning test"]},{label:"Investment",values:["$2,000 to $5,000","$5,000 build + $2,500/mo CRO"]}]},extraFaqs:[{question:"How much does a funnels and CRO program cost?",answer:"Single funnel builds with landing page, lead magnet, and email sequence start at $5,000. Complex multi-offer systems run $10,000 to $30,000. Ongoing CRO programs start at $2,500 per month when you have enough traffic for meaningful tests."},{question:"Do I need a funnel build and CRO at the same time?",answer:"Not always. If you already have traffic, we can start with a CRO audit and testing. If you are launching from scratch, we build the system and optimize from day one so you never go live blind."},{question:"How long before we see conversion lift?",answer:"Funnel builds launch in 4 to 8 weeks. A/B tests usually reach significance in 2 to 4 weeks depending on traffic. Most clients see measurable lift within the first 60 to 90 days of optimization."},{question:"How much traffic do I need for A/B testing?",answer:"About 1,000 monthly sessions on pages being tested. Lower-traffic funnels still benefit from audit-driven UX fixes, heatmap insights, and qualitative research before formal tests."},{question:"Can you connect funnels to our CRM?",answer:"Yes. We integrate with HubSpot, Salesforce, ActiveCampaign, GoHighLevel, and most CRMs. Leads flow automatically with source tags, and sales gets notified when scoring thresholds are hit."}]}},es:{seo:{metaTitle:"Agencia SEO para Generaci\xf3n de Leads | KINEXIS Digital",metaDescription:"Contrata una agencia SEO enfocada en leads calificados, no en posiciones vac\xedas. Auditor\xedas t\xe9cnicas, estrategia de contenido y link building ligados a ingresos. Planes desde $2,500/mes.",hero:{label:"Servicios SEO",line1:"Posiciona en b\xfasquedas",line2:"que realmente convierten.",subtitle:"SEO org\xe1nico para negocios de servicios.|Atacamos las keywords que tus compradores buscan antes de llamar."},answerBlock:"Nuestros servicios SEO incluyen auditor\xedas t\xe9cnicas, investigaci\xf3n de keywords, optimizaci\xf3n on-page, producci\xf3n de contenido y adquisici\xf3n de enlaces ligados a metas de ingresos. La mayor\xeda de clientes invierte entre $2,500 y $8,000 al mes seg\xfan competencia y alcance. Normalmente ves movimiento en posiciones en 60 a 90 d\xedas, con crecimiento real de leads entre el mes 4 y el 6.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Programas SEO No Generan Ingresos",intro:"Tr\xe1fico sin pipeline es solo una l\xednea en un dashboard. Muchas empresas pagan SEO que posiciona t\xe9rminos incorrectos o corrige problemas que nunca mueven ingresos.",points:["Las agencias reportan posiciones e impresiones mientras los leads calificados se mantienen planos.","Se publica contenido sin intenci\xf3n de keyword ni rutas de conversi\xf3n definidas.","Se acumulan correcciones t\xe9cnicas sin conexi\xf3n clara con las p\xe1ginas que realmente venden.","El link building prioriza volumen en lugar de autoridad en tu mercado real."]},solution:{title:"SEO Construido Alrededor de Keywords que Compran",intro:"Empezamos con las keywords que tus mejores clientes buscan antes de llamar a un competidor. Cada p\xe1gina, enlace y correcci\xf3n t\xe9cnica apoya ese camino.",points:["Mapas de keywords ligados a p\xe1ginas de servicio, landing pages y contenido que convierte.","SEO t\xe9cnico que elimina problemas de rastreo que bloquean tus URLs de mayor valor.","Contenido y trabajo on-page orientado a intenci\xf3n comercial y transaccional.","Reportes de leads, costo por adquisici\xf3n e ingresos, no solo cambios de posici\xf3n."]},deliverables:{title:"Qu\xe9 Incluye Nuestro Programa SEO",subtitle:"Un sistema completo de crecimiento org\xe1nico, no una checklist mensual.",items:[{title:"Auditor\xeda SEO T\xe9cnica y Plan de Correcci\xf3n",description:"An\xe1lisis de rastreo, revisi\xf3n de Core Web Vitals, correcciones de indexaci\xf3n y schema markup en p\xe1ginas prioritarias de ingresos."},{title:"Estrategia de Keywords y Contenido",description:"Investigaci\xf3n de keywords con intenci\xf3n de compra, brechas de contenido y calendario editorial alineado a tu embudo de ventas."},{title:"Optimizaci\xf3n On-Page",description:"Title tags, encabezados, enlaces internos y estructura de p\xe1gina en las URLs que generan leads."},{title:"Producci\xf3n de Contenido",description:"P\xe1ginas de servicio, art\xedculos de blog y landing pages escritas para intenci\xf3n de b\xfasqueda y conversi\xf3n."},{title:"Link Building y PR Digital",description:"Outreach, colocaciones como invitado y enlaces de autoridad desde sitios relevantes de tu industria."},{title:"Reporte Mensual de Rendimiento",description:"Posiciones, tr\xe1fico, leads y pipeline ligados a keywords y p\xe1ginas espec\xedficas sobre las que puedes actuar."}]},comparison:{title:"Agencia SEO vs. Contratar In-House",subtitle:"Qu\xe9 obtienes al trabajar con un equipo SEO dedicado.",layout:"ledger",columns:[{header:"SEO Manager In-House"},{header:"KINEXIS SEO",highlight:!0}],rows:[{label:"Costo mensual",values:["$6,000 a $9,000 de salario m\xe1s herramientas","$2,500 a $8,000 todo incluido"]},{label:"Tiempo para arrancar",values:["60 a 90 d\xedas para contratar e integrar","2 a 3 semanas para iniciar"]},{label:"T\xe9cnico + contenido + enlaces",values:["Una persona, ancho de banda limitado","Equipo completo en los tres pilares"]},{label:"Stack de herramientas",values:["$500 a $1,200/mes adem\xe1s del salario","Incluido en tu retainer"]},{label:"Reportes de ingresos",values:["A menudo enfocados en tr\xe1fico","Atribuci\xf3n de leads y pipeline integrada"]},{label:"Flexibilidad",values:["Headcount fijo","Escala arriba o abajo seg\xfan resultados"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta el SEO con KINEXIS?",answer:"La mayor\xeda de retainers SEO van de $2,500 a $8,000 al mes seg\xfan competencia del mercado, n\xfamero de ubicaciones y volumen de contenido. Te damos alcance y precio fijos despu\xe9s de una llamada estrat\xe9gica, sin cargos ocultos."},{question:"\xbfCu\xe1nto tarda el SEO en generar leads?",answer:"Espera movimiento temprano en posiciones en 60 a 90 d\xedas. El crecimiento consistente de leads suele aparecer entre el mes 4 y el 6. Industrias competitivas pueden tardar m\xe1s, pero medimos progreso cada mes para que veas qu\xe9 funciona."},{question:"\xbfGarantizan posiciones en la primera p\xe1gina?",answer:"Ninguna agencia \xe9tica garantiza posiciones espec\xedficas. Garantizamos estrategia clara, ejecuci\xf3n consistente y reportes ligados a leads e ingresos. Nuestros clientes han visto crecimiento org\xe1nico de leads del 80% al 140% en el primer a\xf1o."},{question:"\xbfQu\xe9 incluyen sus auditor\xedas SEO?",answer:"Problemas de rastreo t\xe9cnico, velocidad de p\xe1gina, usabilidad m\xf3vil, indexaci\xf3n, brechas on-page, solapamiento de keywords con competidores y revisi\xf3n del perfil de backlinks. Recibes una lista priorizada de correcciones ordenada por impacto en ingresos."}]},"local-seo":{metaTitle:"Agencia SEO Local para Marcas Multi-Ubicaci\xf3n | KINEXIS Digital",metaDescription:"Agencia SEO local para negocios que necesitan visibilidad en Google Maps, crecimiento de rese\xf1as y posiciones en el local pack. Optimizaci\xf3n de GBP, citaciones y p\xe1ginas de ubicaci\xf3n desde $2,000/mes.",hero:{label:"Servicios SEO Local",line1:"Aparece en el mapa",line2:"cuando buscan cerca.",subtitle:"Perfil de Google, citas, rese\xf1as y p\xe1ginas locales|para negocios que ganan trabajo a pocos kil\xf3metros."},answerBlock:"Los servicios SEO local incluyen optimizaci\xf3n de Google Business Profile, construcci\xf3n de citaciones, estrategia de rese\xf1as, desarrollo de p\xe1ginas de ubicaci\xf3n y adquisici\xf3n de enlaces locales. Los retainers suelen partir en $2,000 a $5,000 al mes para negocios de una ubicaci\xf3n y escalan para marcas multi-ubicaci\xf3n. El movimiento en el map pack suele aparecer en 30 a 60 d\xedas.",problem:{title:"Por Qu\xe9 los Negocios Locales Pierden Frente a Competidores en Google Maps",intro:"Aparecer en el local pack es c\xf3mo la mayor\xeda de negocios de servicios se encuentran. Si tu GBP est\xe1 incompleto o tus citaciones son inconsistentes, le est\xe1s entregando trabajos a la competencia.",points:["Los perfiles de Google Business Profile quedan sin optimizar, con categor\xedas incorrectas y fotos d\xe9biles.","Inconsistencias de NAP en directorios confunden a Google y da\xf1an posiciones locales.","Los competidores acumulan rese\xf1as m\xe1s r\xe1pido mientras tu perfil parece inactivo.","Las p\xe1ginas de ubicaci\xf3n son pobres o no existen, y las b\xfasquedas por ciudad van a competidores nacionales."]},solution:{title:"SEO Local que Te Pone en el Mapa",intro:"Tratamos cada ubicaci\xf3n como su propio mercado. GBP, citaciones, rese\xf1as y contenido local trabajan juntos para ganar las b\xfasquedas que se convierten en llamadas del mismo d\xeda.",points:["Optimizaci\xf3n de GBP con categor\xedas, servicios, publicaciones, fotos y Q&A alineados a intenci\xf3n de b\xfasqueda.","Limpieza y construcci\xf3n de citaciones en los directorios que importan en tu industria.","Sistemas de generaci\xf3n de rese\xf1as que aumentan volumen sin violar pol\xedticas de plataformas.","Landing pages por ubicaci\xf3n construidas para posicionar keywords de ciudad y barrio."]},deliverables:{title:"Entregables SEO Local",subtitle:"Todo lo necesario para posicionarte localmente y convertir visibilidad en mapas en ingresos.",items:[{title:"Gesti\xf3n de Google Business Profile",description:"Optimizaci\xf3n de perfil, publicaciones semanales, actualizaci\xf3n de fotos, listado de servicios y seguimiento de rendimiento."},{title:"Auditor\xeda y Construcci\xf3n de Citaciones",description:"Correcci\xf3n de consistencia NAP y nuevos listados en directorios relevantes de la industria y agregadores de datos."},{title:"Estrategia y Monitoreo de Rese\xf1as",description:"Flujos de solicitud de rese\xf1as, plantillas de respuesta y seguimiento de reputaci\xf3n por ubicaci\xf3n."},{title:"Desarrollo de P\xe1ginas de Ubicaci\xf3n",description:"P\xe1ginas \xfanicas por ciudad y barrio con contenido local, schema e interlinking interno."},{title:"Link Building Local",description:"Patrocinios, alianzas locales y colocaciones comunitarias que construyen autoridad geogr\xe1fica."},{title:"Reporte de Posiciones Locales y Leads",description:"Seguimiento del map pack, call tracking, solicitudes de direcciones y volumen de leads por ubicaci\xf3n."}]},comparison:{title:"SEO Local: DIY vs. Agencia",subtitle:"Compara gestionar b\xfasqueda local por tu cuenta contra un programa SEO local dedicado.",layout:"ledger",columns:[{header:"DIY / Herramienta SEO Gen\xe9rica"},{header:"KINEXIS SEO Local",highlight:!0}],rows:[{label:"Experiencia en GBP",values:["Configuraci\xf3n b\xe1sica de perfil","Optimizaci\xf3n y publicaciones continuas"]},{label:"Gesti\xf3n de citaciones",values:["Actualizaciones manuales propensas a error","Monitoreo automatizado y limpieza"]},{label:"Velocidad de rese\xf1as",values:["Espor\xe1dica, sin sistema","Proceso estructurado de generaci\xf3n de rese\xf1as"]},{label:"Soporte multi-ubicaci\xf3n",values:["Un perfil a la vez","Estrategia centralizada por mercado"]},{label:"Contenido local",values:["P\xe1ginas de ciudad duplicadas","P\xe1ginas \xfanicas con se\xf1ales locales"]},{label:"Timeline de resultados",values:["Impredecible","Ganancias en map pack a menudo en 30 a 60 d\xedas"]}]},extraFaqs:[{question:"\xbfEn qu\xe9 se diferencia el SEO local del SEO regular?",answer:"El SEO regular apunta a posiciones org\xe1nicas amplias a nivel nacional o regional. El SEO local se enfoca en visibilidad del map pack, Google Business Profile, citaciones, rese\xf1as y p\xe1ginas de ubicaci\xf3n. Si tus clientes buscan 'cerca de m\xed' o por nombre de ciudad, necesitas SEO local espec\xedficamente."},{question:"\xbfCu\xe1nto cuesta el SEO local?",answer:"Negocios de una ubicaci\xf3n suelen invertir $2,000 a $5,000 al mes. Marcas multi-ubicaci\xf3n escalan de $3,500 a $10,000+ seg\xfan n\xfamero de mercados y competencia. Cotizamos despu\xe9s de revisar tus ubicaciones y visibilidad actual."},{question:"\xbfCu\xe1ntas rese\xf1as de Google necesito?",answer:"No hay un n\xfamero fijo, pero la mayor\xeda de mercados locales competitivos requieren 50 a 100+ rese\xf1as para mantenerse en el top tres del mapa. Nos enfocamos en velocidad mensual consistente de rese\xf1as y respuestas de calidad, no en picos \xfanicos."},{question:"\xbfPueden gestionar m\xfaltiples perfiles de Google Business?",answer:"S\xed. Gestionamos cuentas GBP multi-ubicaci\xf3n con contenido espec\xedfico por ubicaci\xf3n, flujos de rese\xf1as y reportes de rendimiento para cada mercado. Es una de nuestras fortalezas para franquicias y negocios con varias sucursales."}]},"ppc-management":{metaTitle:"Agencia de Gesti\xf3n PPC Multi-Canal | KINEXIS Digital",metaDescription:"Gesti\xf3n PPC completa en Google, Meta, LinkedIn y Microsoft Ads. Un solo equipo, presupuestos unificados y reportes ROAS. Gesti\xf3n desde 15% del ad spend o m\xednimo $2,500/mes.",hero:{label:"Gesti\xf3n PPC",line1:"Un solo equipo en",line2:"cada canal que pagas.",subtitle:"Google, Meta, LinkedIn y Microsoft, gestionados juntos.|El presupuesto sigue al costo por lead calificado, no al que m\xe1s vendi\xf3."},answerBlock:"La gesti\xf3n PPC cubre estrategia, configuraci\xf3n de campa\xf1as, optimizaci\xf3n de pujas, coordinaci\xf3n creativa y tracking de conversiones en Google, Meta, LinkedIn y Microsoft Ads. Las tarifas suelen ser 15% del ad spend con m\xednimo mensual de $2,500, o retainer fijo para cuentas grandes. La mayor\xeda de cuentas estabiliza CPL en 45 a 60 d\xedas desde el lanzamiento.",problem:{title:"Por Qu\xe9 Cuentas de Anuncios Aisladas Desperdician Presupuesto",intro:"Correr Google y Meta por separado sin estrategia unificada hace que los canales compitan entre s\xed y nadie tenga la foto completa.",points:["Los presupuestos se quedan en plataformas de bajo rendimiento porque nadie compara CPL entre canales.","El tracking se rompe entre plataformas de anuncios, CRM y sitio web, y los n\xfameros de ROAS no son confiables.","Creativos y landing pages se construyen por canal sin un marco de pruebas compartido.","Equipos internos o freelancers gestionan una plataforma cada uno, ralentizando decisiones y duplicando gasto."]},solution:{title:"Un Solo Equipo Gestionando Cada Canal Pagado",intro:"Operamos todo tu stack de paid media con metas compartidas, tracking unificado y reasignaci\xf3n semanal de presupuesto seg\xfan lo que realmente genera leads.",points:["Estrategia cross-channel con asignaci\xf3n de presupuesto ligada a costo por lead calificado, no preferencia de plataforma.","Tracking de conversiones unificado de clic a CRM para conocer ROAS real por canal y campa\xf1a.","Coordinaci\xf3n de creativos y landing pages para mantener mensaje consistente en Google y social.","Ciclos de optimizaci\xf3n semanal en todas las plataformas en lugar de revisiones mensuales en una sola cuenta."]},deliverables:{title:"Entregables de Gesti\xf3n PPC",subtitle:"Gesti\xf3n de paid media full-funnel en cada plataforma que operes.",items:[{title:"Estrategia Multi-Canal y Plan de Presupuesto",description:"Recomendaciones de mix de canales, asignaci\xf3n mensual de presupuesto y metas KPI por plataforma."},{title:"Construcci\xf3n y Lanzamiento de Campa\xf1as",description:"Estructura de cuenta, segmentaci\xf3n de audiencias, copy de anuncios y extensiones en Google, Meta, LinkedIn y Microsoft."},{title:"Configuraci\xf3n de Tracking de Conversiones",description:"GA4, p\xedxeles de plataforma, integraci\xf3n CRM e importaci\xf3n de conversiones offline para atribuci\xf3n precisa."},{title:"Optimizaci\xf3n Semanal de Pujas y Presupuesto",description:"Ajustes de pujas, movimientos de presupuesto, gesti\xf3n de keywords negativas y refinamiento de audiencias."},{title:"Marco de Pruebas Creativas",description:"Rotaci\xf3n de copy y creativos con pruebas A/B estructuradas y benchmarks de rendimiento."},{title:"Dashboard Unificado de Rendimiento",description:"Reportes cross-channel de gasto, CPL, ROAS y valor de pipeline en una sola vista."}]},comparison:{title:"PPC Multi-Canal: Gestores Separados vs. KINEXIS",subtitle:"Qu\xe9 cambia cuando un solo equipo gestiona todo tu programa de paid media.",layout:"impact",columns:[{header:"Gestores por Canal Separados"},{header:"KINEXIS Gesti\xf3n PPC",highlight:!0}],rows:[{label:"Alineaci\xf3n estrat\xe9gica",values:["Cada plataforma optimiza aislada","Metas unificadas y KPIs compartidos"]},{label:"Flexibilidad de presupuesto",values:["Presupuestos aislados, cambios lentos","Reasignaci\xf3n semanal a mejores performers"]},{label:"Consistencia de tracking",values:["Definiciones distintas de conversi\xf3n","Un marco de tracking en todos los canales"]},{label:"Costo de gesti\xf3n",values:["15 a 20% por plataforma se acumula","Tarifa \xfanica, menor overhead total"]},{label:"Reportes",values:["Varios dashboards, n\xfameros en conflicto","Un dashboard con ROAS cross-channel"]},{label:"Velocidad de decisiones",values:["Reuniones de coordinaci\xf3n ralentizan cambios","Ajustes de presupuesto y pujas el mismo d\xeda"]}]},extraFaqs:[{question:"\xbfQu\xe9 plataformas gestionan bajo gesti\xf3n PPC?",answer:"Google Ads, Meta Ads (Facebook e Instagram), LinkedIn Ads y Microsoft Ads. Coordinamos presupuestos y reportes en las cuatro. Si solo necesitas una plataforma, nuestros servicios de Google Ads o Meta Ads pueden ser mejor opci\xf3n."},{question:"\xbfC\xf3mo se cotiza la gesti\xf3n PPC?",answer:"Cobramos 15% del ad spend mensual con retainer m\xednimo de $2,500, o tarifa fija para cuentas que invierten $50,000+ al mes. El ad spend se factura directo a las plataformas en tus cuentas. Siempre eres due\xf1o de tus cuentas de anuncios."},{question:"\xbfQu\xe9 nivel de ad spend requieren?",answer:"Trabajamos mejor con negocios que invierten $5,000 a $100,000+ al mes en ad spend total entre canales. Por debajo de $5,000, un programa de un solo canal suele ser m\xe1s eficiente."},{question:"\xbfEn qu\xe9 se diferencia la gesti\xf3n PPC de su servicio de anuncios pagados?",answer:"Anuncios pagados es nuestra entrada para negocios que exploran paid media. Gesti\xf3n PPC es el programa multi-canal completo con estrategia cross-platform, tracking unificado y optimizaci\xf3n continua en Google, Meta, LinkedIn y Microsoft."}]},"google-ads":{metaTitle:"Agencia de Gesti\xf3n Google Ads | Search y PMax | KINEXIS Digital",metaDescription:"Gesti\xf3n Google Ads para Search, Shopping y Performance Max. Optimizaci\xf3n de Quality Score, tracking de conversiones y campa\xf1as enfocadas en ROAS. Desde $1,500/mes de gesti\xf3n.",hero:{label:"Gesti\xf3n Google Ads",line1:"Google Ads que protegen",line2:"tu margen, no el de Google.",subtitle:"Search, Shopping y PMax para leads calificados.|Corregimos estructura de cuenta y tracking que inflan el costo por lead."},answerBlock:"La gesti\xf3n Google Ads incluye auditor\xeda de cuenta, estructura de campa\xf1as, estrategia de keywords, copy de anuncios, gesti\xf3n de pujas, mejora de Quality Score y tracking de conversiones para Search, Shopping y Performance Max. Las tarifas de gesti\xf3n parten en $1,500 al mes m\xe1s ad spend. La mayor\xeda de cuentas estabiliza CPL en 30 a 45 d\xedas.",problem:{title:"Por Qu\xe9 las Cuentas Google Ads Desperdician Presupuesto",intro:"Google facilita gastar dinero y dificulta saber qu\xe9 realmente impulsa ingresos. La mayor\xeda de cuentas que auditamos tienen problemas estructurales que inflan el costo por lead.",points:["Keywords broad match y recomendaciones auto-aplicadas inflan gasto en b\xfasquedas irrelevantes.","El tracking de conversiones cuenta formularios y page views en lugar de leads calificados.","La estructura mezcla brand, competidor y t\xe9rminos gen\xe9ricos sin segmentaci\xf3n adecuada.","Las landing pages no coinciden con la intenci\xf3n del anuncio, baja el Quality Score y sube el CPC."]},solution:{title:"Google Ads Construido para Quality Score y ROAS",intro:"Reestructuramos cuentas alrededor de intenci\xf3n de b\xfasqueda, ajustamos tracking a conversiones calificadas y optimizamos pujas seg\xfan lo que tu CRM confirma como pipeline real.",points:["Arquitectura de campa\xf1as que separa keywords de brand, competidor y gen\xe9ricas de alta intenci\xf3n.","Gesti\xf3n de keywords negativas y revisiones de search terms para cortar gasto desperdiciado cada semana.","Alineaci\xf3n de copy y landing pages que mejora Quality Score y reduce CPC.","Estrategias de puja ligadas a datos de conversi\xf3n offline cuando tu ciclo de venta va m\xe1s all\xe1 del clic."]},deliverables:{title:"Entregables de Gesti\xf3n Google Ads",subtitle:"Todo lo necesario para operar campa\xf1as Search, Shopping y PMax rentables.",items:[{title:"Auditor\xeda y Reestructuraci\xf3n de Cuenta",description:"Revisi\xf3n completa de campa\xf1as, ad groups, keywords, match types y conversion actions con plan de reconstrucci\xf3n."},{title:"Investigaci\xf3n de Keywords y Listas Negativas",description:"Keywords de alta intenci\xf3n m\xe1s listas negativas continuas para bloquear tr\xe1fico irrelevante."},{title:"Gesti\xf3n de Copy y Extensiones",description:"Responsive search ads, callouts, sitelinks y structured snippets probados con cadencia regular."},{title:"Configuraci\xf3n Performance Max y Shopping",description:"Optimizaci\xf3n de feed, asset groups, se\xf1ales de audiencia y estructura de listing groups para e-commerce."},{title:"Tracking de Conversiones y Atribuci\xf3n",description:"GA4, Google Tag Manager, enhanced conversions e integraci\xf3n CRM para tracking preciso de leads."},{title:"Optimizaci\xf3n Semanal y Reportes",description:"Ajustes de pujas, pacing de presupuesto, revisiones de search terms y reportes mensuales de ROAS y CPL."}]},comparison:{title:"Google Ads: Autogestionado vs. KINEXIS",subtitle:"Compara operar Google Ads in-house contra un equipo de gesti\xf3n dedicado.",layout:"impact",columns:[{header:"Autogestionado / Freelancer"},{header:"KINEXIS Google Ads",highlight:!0}],rows:[{label:"Estructura de cuenta",values:["Campa\xf1as planas, intenci\xf3n mezclada","Segmentada por intenci\xf3n y etapa del embudo"]},{label:"Frecuencia de optimizaci\xf3n",values:["Mensual o cuando se acaba el presupuesto","Revisiones semanales de search terms y pujas"]},{label:"Tracking de conversiones",values:["Page views contados como conversiones","Tracking de leads calificados con sync CRM"]},{label:"Enfoque en Quality Score",values:["Rara vez monitoreado","Alineaci\xf3n activa de anuncios y landing pages"]},{label:"Experiencia Shopping / PMax",values:["Experiencia limitada en feed y assets","Gesti\xf3n dedicada de campa\xf1as e-commerce"]},{label:"Mejora t\xedpica de CPL",values:["L\xednea base o en aumento","Reducci\xf3n del 20% al 40% en 90 d\xedas"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta la gesti\xf3n Google Ads?",answer:"Las tarifas de gesti\xf3n parten en $1,500 al mes para cuentas bajo $10,000 de ad spend. Cuentas m\xe1s grandes se cotizan al 12% al 15% del gasto. Tu presupuesto de anuncios se paga directo a Google. Recomendamos m\xednimo $3,000 mensuales de ad spend para reunir datos suficientes de optimizaci\xf3n."},{question:"\xbfGestionan campa\xf1as Performance Max?",answer:"S\xed. Construimos y optimizamos Performance Max con asset groups correctos, se\xf1ales de audiencia y datos de feed para e-commerce. Tambi\xe9n monitoreamos search term insights y tr\xe1fico de brand para evitar que PMax canibalice tus campa\xf1as Search."},{question:"\xbfQu\xe9 tan r\xe1pido ver\xe9 resultados de Google Ads?",answer:"Las campa\xf1as Search suelen generar leads en la primera semana de lanzamiento. CPL estable y optimizado normalmente toma 30 a 45 d\xedas mientras refinamos keywords, negativas y pujas. Shopping y PMax pueden necesitar 2 a 3 semanas para que el algoritmo se estabilice."},{question:"\xbfSer\xe9 due\xf1o de mi cuenta Google Ads?",answer:"Siempre. Trabajamos dentro de tu cuenta con acceso admin completo. Si te vas, te quedas con cada campa\xf1a, lista de keywords y setup de conversiones que construimos."}]},"meta-ads":{metaTitle:"Agencia de Gesti\xf3n Meta Ads | Facebook e Instagram | KINEXIS Digital",metaDescription:"Gesti\xf3n Meta Ads para Facebook e Instagram. Prospecci\xf3n, retargeting y pruebas creativas construidas para ROAS. Gesti\xf3n desde $1,500/mes m\xe1s ad spend.",hero:{label:"Gesti\xf3n Meta Ads",line1:"Meta Ads que siguen",line2:"funcionando tras el lanzamiento.",subtitle:"Prospecci\xf3n y retargeting en Facebook e Instagram.|Pruebas creativas que combaten la fatiga antes de que suba el CPM."},answerBlock:"La gesti\xf3n Meta Ads cubre investigaci\xf3n de audiencias, estructura de campa\xf1as, pruebas de creativos, embudos de retargeting y tracking de conversiones basado en p\xedxel en Facebook e Instagram. La gesti\xf3n parte en $1,500 al mes. La mayor\xeda de cuentas necesita $3,000 a $15,000 de ad spend mensual y 2 a 4 semanas de pruebas creativas para encontrar ROAS estable.",problem:{title:"Por Qu\xe9 las Cuentas Meta Ads se Estancan Despu\xe9s de la Primera Semana",intro:"Meta premia creativos frescos y segmentaci\xf3n clara de audiencias. La mayor\xeda de negocios lanza unos pocos anuncios, ve resultados tempranos desvanecerse y no entiende por qu\xe9 el CPM sigue subiendo.",points:["La fatiga creativa aparece porque nadie produce y prueba variaciones nuevas con regularidad.","Las audiencias se solapan entre prospecci\xf3n y retargeting, inflando costos y enturbiando atribuci\xf3n.","El tracking de p\xedxel y CAPI pierde conversiones, y el algoritmo optimiza hacia eventos incorrectos.","El gasto va a targeting amplio sin lookalikes ni stacks de intereses construidos desde datos de clientes."]},solution:{title:"Campa\xf1as Meta con Pruebas Creativas Estructuradas",intro:"Construimos embudos de prospecci\xf3n y retargeting con un pipeline creativo que mantiene anuncios frescos y audiencias limpias para que el algoritmo tenga buenos datos.",points:["Estructura de campa\xf1as que separa audiencias de prospecci\xf3n fr\xeda, engagement tibio y retargeting caliente.","Sprints de prueba creativa con 3 a 5 variaciones nuevas cada dos semanas para combatir fatiga.","Setup de Conversions API y p\xedxel que alimenta datos precisos de compra y leads de vuelta a Meta.","Lookalikes y audiencias custom construidas desde tu CRM, visitantes web y compradores previos."]},deliverables:{title:"Entregables de Gesti\xf3n Meta Ads",subtitle:"Gesti\xf3n completa de campa\xf1as Facebook e Instagram con creativos en el centro.",items:[{title:"Auditor\xeda de Cuenta y P\xedxel",description:"Revisi\xf3n de Business Manager, salud del p\xedxel, setup CAPI y mapeo de eventos para tracking preciso."},{title:"Estrategia y Construcci\xf3n de Audiencias",description:"Audiencias custom, lookalikes, stacks de intereses y listas de exclusi\xf3n para prospecci\xf3n y retargeting limpios."},{title:"Estructura y Lanzamiento de Campa\xf1as",description:"Campa\xf1as de prospecci\xf3n, retargeting y cat\xe1logo con asignaci\xf3n de presupuesto y estrategias de puja correctas."},{title:"Programa de Pruebas Creativas",description:"Variaciones de copy, imagen y video probadas cada quince d\xedas con reglas claras de escalar o pausar."},{title:"Alineaci\xf3n de Landing Pages y Embudo",description:"Coordinaci\xf3n con tus landing pages o las nuestras para que la promesa del anuncio coincida con la experiencia de p\xe1gina."},{title:"Reportes de Rendimiento",description:"Gasto semanal, CPM, CTR, CPL, ROAS y desglose por creativo con recomendaciones de siguiente paso."}]},comparison:{title:"Meta Ads: Impulsar Publicaciones vs. Campa\xf1as Gestionadas",subtitle:"La diferencia entre impulsar posts por tu cuenta y gesti\xf3n profesional de Meta Ads.",layout:"impact",columns:[{header:"Impulsar Post / DIY"},{header:"KINEXIS Meta Ads",highlight:!0}],rows:[{label:"Precisi\xf3n de targeting",values:["Amplio, solo por intereses","Audiencias custom, lookalikes y exclusiones"]},{label:"Pruebas creativas",values:["Un anuncio, configurar y olvidar","Sprints creativos quincenales con 3 a 5 variantes"]},{label:"Embudos de retargeting",values:["Ninguno o visitantes web b\xe1sicos","Retargeting multi-etapa tibio y caliente"]},{label:"Precisi\xf3n de tracking",values:["Solo p\xedxel, brechas iOS","P\xedxel m\xe1s Conversions API"]},{label:"Costo por lead",values:["A menudo 2 a 3x m\xe1s alto","20% a 35% m\xe1s bajo despu\xe9s del periodo de optimizaci\xf3n"]},{label:"Reportes",values:["M\xe9tricas vanidosas de plataforma","CPL, ROAS y desglose por creativo"]}]},extraFaqs:[{question:"\xbfCu\xe1nto deber\xeda invertir en Meta Ads?",answer:"Recomendamos $3,000 a $15,000 al mes en ad spend para la mayor\xeda de cuentas B2B y e-commerce. Por debajo de $3,000, el algoritmo no tiene datos suficientes para optimizar bien. Las tarifas de gesti\xf3n parten en $1,500 al mes adem\xe1s del ad spend."},{question:"\xbfCrean creativos de anuncio para campa\xf1as Meta?",answer:"S\xed. Escribimos copy y coordinamos creativos de imagen y video como parte del programa de gesti\xf3n. Si necesitas producci\xf3n de video completa, nuestro servicio de video marketing lo cubre por separado."},{question:"\xbfEn qu\xe9 se diferencia la gesti\xf3n Meta Ads de la gesti\xf3n PPC?",answer:"Gesti\xf3n PPC cubre Google, Meta, LinkedIn y Microsoft como un programa cross-channel. Gesti\xf3n Meta Ads es dedicada solo a Facebook e Instagram, con pruebas creativas y trabajo de audiencias m\xe1s profundo espec\xedfico de Meta."},{question:"\xbfCu\xe1nto tarda Meta Ads en volverse rentable?",answer:"Espera 2 a 4 semanas de pruebas creativas antes de encontrar combinaciones ganadoras de anuncio y audiencia. ROAS estable normalmente llega entre las semanas 4 y 8 seg\xfan tu oferta, volumen creativo y nivel de gasto mensual."}]},"paid-ads":{metaTitle:"Agencia de Anuncios Pagados para Generaci\xf3n de Leads | KINEXIS Digital",metaDescription:"Agencia de anuncios pagados para negocios listos para invertir en Google, Meta y LinkedIn. Estrategia, setup y gesti\xf3n enfocados en leads calificados. Programas desde $3,000/mes.",hero:{label:"Servicios de Anuncios Pagados",line1:"Paid media que empieza",line2:"en el canal correcto.",subtitle:"Para negocios que lanzan o escalan anuncios.|Elegimos canales, construimos campa\xf1as que convierten y medimos costo por lead."},answerBlock:"Los servicios de anuncios pagados cubren selecci\xf3n de canal, estrategia de campa\xf1as, creaci\xf3n de anuncios, alineaci\xf3n de landing pages, tracking de conversiones y optimizaci\xf3n continua en Google, Meta y LinkedIn. Ad spend y gesti\xf3n combinados suelen partir en $3,000 a $10,000 al mes. La mayor\xeda de clientes ve sus primeros leads calificados en 7 a 14 d\xedas desde el lanzamiento.",problem:{title:"Por Qu\xe9 los Negocios Desperdician Dinero en Publicidad Pagada",intro:"Los anuncios pagados funcionan cuando estrategia, creativos, tracking y landing pages est\xe1n alineados. La mayor\xeda salta a una plataforma sin sistema para medir cu\xe1nto cuesta realmente un lead calificado.",points:["El presupuesto va a la recomendaci\xf3n de plataforma m\xe1s ruidosa en lugar de donde est\xe1n tus compradores.","Los anuncios llevan tr\xe1fico a p\xe1ginas gen\xe9ricas del sitio que nunca se construyeron para convertir visitantes pagados.","Sin tracking de conversiones optimizas hacia clics y formularios, no hacia leads listos para venta.","Las campa\xf1as lanzan sin plan de pruebas, y anuncios de bajo rendimiento corren meses sin revisi\xf3n."]},solution:{title:"Anuncios Pagados con Camino Claro hacia ROAS",intro:"Alineamos tu oferta y audiencia con los canales correctos, construimos campa\xf1as enfocadas en conversi\xf3n y optimizamos semanalmente seg\xfan calidad real de leads desde tu CRM.",points:["Recomendaci\xf3n de canal seg\xfan d\xf3nde buscan y navegan tus compradores, no hype de plataforma.","Construcci\xf3n de campa\xf1as y landing pages dise\xf1adas para convertir tr\xe1fico pagado desde el d\xeda uno.","Setup de tracking que conecta clics de anuncios con leads en CRM para conocer costo real de adquisici\xf3n.","Pruebas estructuradas en copy, audiencias y ofertas con criterios claros de escalar o pausar."]},deliverables:{title:"Entregables del Programa de Anuncios Pagados",subtitle:"De estrategia a ejecuci\xf3n para negocios que inician o escalan paid media.",items:[{title:"Estrategia de Paid Media y Plan de Canales",description:"Selecci\xf3n de plataforma, asignaci\xf3n de presupuesto, metas KPI y an\xe1lisis competitivo antes de gastar."},{title:"Construcci\xf3n y Lanzamiento de Campa\xf1as",description:"Setup de cuenta, segmentaci\xf3n de audiencias, copy de anuncios y creativos en las plataformas elegidas."},{title:"Implementaci\xf3n de Tracking de Conversiones",description:"P\xedxeles, tags, eventos GA4 e integraci\xf3n CRM para que cada lead se atribuya a su fuente."},{title:"Desarrollo u Optimizaci\xf3n de Landing Pages",description:"Landing pages dedicadas construidas para tr\xe1fico pagado con mensaje alineado a tus anuncios."},{title:"Optimizaci\xf3n Semanal y Pruebas A/B",description:"Ajustes de pujas, refinamiento de audiencias, rotaci\xf3n de anuncios y pacing de presupuesto seg\xfan datos de leads."},{title:"Revisi\xf3n Mensual de Rendimiento",description:"Reportes de gasto, CPL, ROAS y pipeline con recomendaciones para el presupuesto del mes siguiente."}]},comparison:{title:"Para Empezar: Una Plataforma vs. Programa Pagado Estrat\xe9gico",subtitle:"Qu\xe9 ganas con un enfoque estructurado de anuncios pagados en lugar de gasto ad hoc.",layout:"progression",columns:[{header:"Ad Hoc / Una Plataforma"},{header:"Programa KINEXIS Anuncios Pagados",highlight:!0},{header:"Gesti\xf3n PPC Completa"}],rows:[{label:"Estrategia de canal",values:["Una plataforma, sin comparaci\xf3n","Selecci\xf3n del canal ideal","Todos los canales coordinados"]},{label:"Landing pages",values:["Homepage o p\xe1gina gen\xe9rica","P\xe1ginas de conversi\xf3n dedicadas","P\xe1ginas dedicadas por canal"]},{label:"Setup de tracking",values:["P\xedxel b\xe1sico o ninguno","Atribuci\xf3n completa a CRM","Atribuci\xf3n cross-channel"]},{label:"Optimizaci\xf3n",values:["Configurar y olvidar","Revisiones semanales","Ajustes diarios cross-channel"]},{label:"Ideal para",values:["Probar presupuesto peque\xf1o","Escalar un canal probado","Multi-canal con $5K+/mes de gasto"]},{label:"Inversi\xf3n inicial",values:["$500 a $1,500/mes","$3,000 a $10,000/mes","$5,000 a $100,000+/mes de ad spend"]}]},extraFaqs:[{question:"\xbfCon qu\xe9 plataforma de anuncios pagados deber\xeda empezar?",answer:"Depende de tu audiencia. Servicios B2B suelen empezar con Google Search. E-commerce a menudo divide entre Google Shopping y Meta. Servicios locales se benefician de Google Search m\xe1s retargeting Meta. Recomendamos el mix correcto en tu llamada estrat\xe9gica."},{question:"\xbfEn qu\xe9 se diferencian anuncios pagados de gesti\xf3n PPC?",answer:"Anuncios pagados es nuestro programa para negocios que lanzan o escalan paid media con estrategia de canal y ejecuci\xf3n de campa\xf1as. Gesti\xf3n PPC es nuestro servicio multi-canal avanzado para cuentas que invierten $5,000+ al mes en Google, Meta, LinkedIn y Microsoft con optimizaci\xf3n unificada."},{question:"\xbfCu\xe1l es el presupuesto m\xednimo para anuncios pagados?",answer:"Recomendamos al menos $3,000 al mes combinando ad spend y tarifas de gesti\xf3n. Por debajo de eso no hay datos suficientes para optimizar bien. Programas solo Google pueden empezar m\xe1s bajo si usas directamente nuestro servicio de gesti\xf3n Google Ads."},{question:"\xbfConstruyen landing pages para campa\xf1as pagadas?",answer:"S\xed. Landing pages dedicadas est\xe1n incluidas o disponibles en la mayor\xeda de programas de anuncios pagados. Enviar tr\xe1fico pagado a tu homepage t\xedpicamente desperdicia 30% a 50% del presupuesto en visitantes que nunca convierten."}]},"web-design":{metaTitle:"Agencia de Dise\xf1o Web para Generaci\xf3n de Leads | KINEXIS Digital",metaDescription:"Dise\xf1o web a medida construido para convertir visitantes en leads. Estrategia, UX, desarrollo y CRO incluidos. Proyectos web desde $8,000 a $35,000, entregados en 6 a 10 semanas.",hero:{label:"Servicios de Dise\xf1o Web",line1:"Sitios que se ven bien",line2:"y realmente convierten.",subtitle:"Dise\xf1os a medida donde cada p\xe1gina y formulario genera llamadas.|No otra plantilla con tu logo encima."},answerBlock:"Los servicios de dise\xf1o web incluyen discovery, estrategia UX, dise\xf1o custom, desarrollo responsive, setup de CMS, estructura SEO b\xe1sica y layouts enfocados en conversi\xf3n. Los proyectos van de $8,000 para sitios enfocados a $35,000+ para sitios empresariales multi-p\xe1gina. La entrega t\xedpica es 6 a 10 semanas desde kickoff hasta lanzamiento.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Sitios Web Empresariales No Convierten",intro:"Un sitio bonito que no genera leads es un gasto, no un activo. Plantillas y builders DIY se ven bien pero pierden la estrategia que convierte tr\xe1fico en ingresos.",points:["Las homepages intentan decir todo y no gu\xedan al visitante a ning\xfan lugar espec\xedfico.","Los formularios de contacto quedan al final de p\xe1ginas largas sin raz\xf3n clara para completarlos.","La experiencia m\xf3vil se rompe en p\xe1ginas clave, perdiendo m\xe1s de la mitad de tu tr\xe1fico.","Las puntuaciones de velocidad da\xf1an calidad de anuncios y SEO mientras los visitantes rebotan antes de cargar."]},solution:{title:"Sitios Dise\xf1ados Alrededor de Tu Proceso de Ventas",intro:"Mapeamos primero el recorrido de tu comprador, luego dise\xf1amos p\xe1ginas que mueven visitantes de awareness a acci\xf3n con CTAs claros, se\xf1ales de confianza y tiempos de carga r\xe1pidos.",points:["Arquitectura de p\xe1ginas basada en tus servicios, preguntas del comprador y metas de conversi\xf3n.","Dise\xf1o custom que refleja tu marca sin sacrificar velocidad ni usabilidad.","Elementos de conversi\xf3n colocados donde el visitante decide: above the fold, mid-page y exit intent.","Optimizaci\xf3n Core Web Vitals para que tu sitio rinda en b\xfasqueda y campa\xf1as pagadas."]},deliverables:{title:"Entregables del Proyecto de Dise\xf1o Web",subtitle:"De estrategia a lanzamiento, construido para convertir.",items:[{title:"Discovery y Estrategia UX",description:"Investigaci\xf3n de compradores, sitemap, wireframes y mapeo de rutas de conversi\xf3n antes de cualquier dise\xf1o."},{title:"Dise\xf1o Visual Custom",description:"Mockups alineados a marca para p\xe1ginas clave con layouts m\xf3vil y desktop, sin plantillas."},{title:"Desarrollo Responsive",description:"C\xf3digo limpio y r\xe1pido en frameworks modernos con integraci\xf3n CMS para actualizaciones f\xe1ciles de contenido."},{title:"Plantillas de P\xe1gina Enfocadas en Conversi\xf3n",description:"P\xe1ginas de servicio, landing pages y flujos de contacto con formularios, CTAs y se\xf1ales de confianza."},{title:"Base SEO On-Page",description:"Title tags, meta descriptions, schema markup y estructura de sitio lista para crecimiento org\xe1nico."},{title:"Soporte de Lanzamiento y Capacitaci\xf3n",description:"QA testing, setup de analytics, capacitaci\xf3n CMS y 30 d\xedas de ajustes post-lanzamiento."}]},comparison:{title:"Dise\xf1o Web Custom vs. Constructores de Plantillas",subtitle:"Compara un build custom enfocado en conversi\xf3n contra opciones DIY y plantillas.",layout:"contrast",columns:[{header:"Plantilla / Builder DIY"},{header:"KINEXIS Dise\xf1o Web",highlight:!0}],rows:[{label:"Estrategia y UX",values:["Eliges tema, agregas texto","Discovery, wireframes y mapeo de conversi\xf3n"]},{label:"Velocidad de p\xe1gina",values:["Temas pesados, cargas lentas","Optimizado para Core Web Vitals"]},{label:"Dise\xf1o de conversi\xf3n",values:["Layouts gen\xe9ricos","CTAs y formularios colocados por intenci\xf3n"]},{label:"Preparaci\xf3n SEO",values:["B\xe1sica, dependiente de plugins","Estructura y schema integrados"]},{label:"Costo del proyecto",values:["$500 a $3,000","$8,000 a $35,000"]},{label:"Mejora t\xedpica de conversi\xf3n",values:["L\xednea base","Aumento del 25% al 60% con CRO asociado"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta un sitio web custom?",answer:"La mayor\xeda de sitios empresariales van de $8,000 a $35,000 seg\xfan cantidad de p\xe1ginas, funcionalidad custom e integraciones. E-commerce y sitios multi-ubicaci\xf3n pueden superar ese rango. Damos cotizaci\xf3n fija despu\xe9s del discovery."},{question:"\xbfCu\xe1nto tarda un proyecto de dise\xf1o web?",answer:"Sitios empresariales est\xe1ndar toman 6 a 10 semanas desde kickoff hasta lanzamiento. Sitios m\xe1s grandes con funciones custom pueden tomar 10 a 14 semanas. Definimos timeline claro en tu propuesta con checkpoints por hito."},{question:"\xbfRedise\xf1an sitios existentes o solo construyen nuevos?",answer:"Ambos. Redise\xf1amos sitios de bajo rendimiento y construimos nuevos desde cero. Los redise\xf1os suelen incluir auditor\xeda de conversi\xf3n primero para corregir lo roto antes de cambiar el dise\xf1o."},{question:"\xbfEn qu\xe9 CMS construyen?",answer:"Principalmente construimos en Next.js y CMS headless por velocidad y flexibilidad. Para clientes que necesitan WordPress, construimos temas custom sin bloat de page builders."}]},cro:{metaTitle:"Agencia de Optimizaci\xf3n de Conversi\xf3n (CRO) | KINEXIS Digital",metaDescription:"Agencia CRO que aumenta leads y ventas desde tu tr\xe1fico actual. Auditor\xedas, pruebas A/B y correcciones UX con lift medible. Programas desde $2,500/mes o por proyecto.",hero:{label:"Optimizaci\xf3n de Conversi\xf3n",line1:"M\xe1s leads del",line2:"tr\xe1fico que ya tienes.",subtitle:"Encontramos d\xf3nde abandonan los visitantes en tu sitio y landings,|y probamos arreglos para convertir m\xe1s sin subir gasto en anuncios."},answerBlock:"Los servicios CRO incluyen auditor\xedas de conversi\xf3n, an\xe1lisis de heatmaps y sesiones, desarrollo de hip\xf3tesis, pruebas A/B y mejoras UX en p\xe1ginas de alto tr\xe1fico. Retainers parten en $2,500 al mes o por proyecto para optimizaci\xf3n de una sola p\xe1gina. La mayor\xeda de pruebas alcanza significancia estad\xedstica en 2 a 4 semanas.",problem:{title:"Por Qu\xe9 Tu Tr\xe1fico No Se Convierte en Leads",intro:"Traer m\xe1s visitantes a un sitio que no convierte es caro. La mayor\xeda de negocios se enfoca en volumen de tr\xe1fico e ignora las fugas en su embudo de conversi\xf3n.",points:["Las landing pages tienen propuestas de valor poco claras y CTAs d\xe9biles o ausentes.","Los formularios piden demasiada informaci\xf3n de entrada, y los visitantes abandonan.","La UX m\xf3vil se rompe en p\xe1ginas clave de conversi\xf3n mientras la mayor\xeda del tr\xe1fico viene del celular.","Sin marco de pruebas, las mejoras se basan en suposiciones en lugar de datos."]},solution:{title:"Pruebas Sistem\xe1ticas que se Acumulan con el Tiempo",intro:"Auditamos tus p\xe1ginas de mayor tr\xe1fico, identificamos las fugas de conversi\xf3n m\xe1s grandes y ejecutamos pruebas estructuradas que producen lift medible que puedes replicar en todo el sitio.",points:["Auditor\xedas de conversi\xf3n respaldadas por analytics, heatmaps y grabaciones de sesi\xf3n en p\xe1ginas prioritarias.","Pruebas A/B basadas en hip\xf3tesis sobre headlines, CTAs, campos de formulario y layout de p\xe1gina.","Correcciones UX para m\xf3vil, velocidad y navegaci\xf3n que eliminan fricci\xf3n antes de probar.","Reportes de lift en tasa de conversi\xf3n, leads incrementales e impacto en ingresos por prueba."]},deliverables:{title:"Entregables del Programa CRO",subtitle:"Investigaci\xf3n, pruebas e implementaci\xf3n enfocadas en lift de conversi\xf3n medible.",items:[{title:"Auditor\xeda de Conversi\xf3n y Mapa de Oportunidades",description:"Revisi\xf3n de analytics, an\xe1lisis de embudo, heatmaps y grabaciones de sesi\xf3n con lista priorizada de correcciones."},{title:"Desarrollo de Hip\xf3tesis",description:"Ideas de prueba respaldadas por datos, ordenadas por impacto esperado y esfuerzo de implementaci\xf3n."},{title:"Pruebas A/B y Multivariadas",description:"Experimentos estructurados en headlines, CTAs, formularios, layouts y elementos de prueba social."},{title:"Mejoras UX y de Copy",description:"Cambios de copy, dise\xf1o y layout a nivel de p\xe1gina seg\xfan hallazgos de auditor\xeda y resultados de pruebas."},{title:"Optimizaci\xf3n de Formularios y CTAs",description:"Reducci\xf3n de campos, formularios multi-paso, copy de botones y pruebas de ubicaci\xf3n en p\xe1ginas clave."},{title:"Reporte Mensual de Lift",description:"Resultados de pruebas, cambios en tasa de conversi\xf3n, leads incrementales y recomendaciones de rollout."}]},comparison:{title:"CRO: M\xe1s Tr\xe1fico vs. Mejor Conversi\xf3n",subtitle:"Por qu\xe9 optimizar tr\xe1fico existente a menudo supera comprar m\xe1s.",layout:"impact",columns:[{header:"Aumentar Ad Spend 50%"},{header:"Programa KINEXIS CRO",highlight:!0}],rows:[{label:"Costo para agregar 50% m\xe1s leads",values:["50% m\xe1s de presupuesto en anuncios","Retainer $2,500/mes, mismo ad spend"]},{label:"Timeline",values:["Inmediato pero costoso","2 a 8 semanas para resultados de pruebas"]},{label:"Efecto compuesto",values:["Se detiene cuando se detiene el presupuesto","El lift aplica a todas las fuentes de tr\xe1fico"]},{label:"Riesgo",values:["CPL m\xe1s alto si las landing pages siguen d\xe9biles","Bajo riesgo, cambios basados en datos"]},{label:"Lift t\xedpico de conversi\xf3n",values:["0% si las p\xe1ginas son el cuello de botella","15% a 45% en p\xe1ginas optimizadas"]},{label:"Funciona con tr\xe1fico SEO",values:["N/A","S\xed, el lift aplica a org\xe1nico y pagado"]}]},extraFaqs:[{question:"\xbfCu\xe1nto tr\xe1fico necesito para pruebas CRO?",answer:"Recomendamos al menos 1,000 sesiones mensuales en las p\xe1ginas que se prueban para alcanzar significancia estad\xedstica en 2 a 4 semanas. P\xe1ginas de bajo tr\xe1fico a\xfan se benefician de correcciones UX basadas en auditor\xeda sin pruebas A/B formales."},{question:"\xbfQu\xe9 mejora de tasa de conversi\xf3n deber\xeda esperar?",answer:"La mayor\xeda de clientes ve lift del 15% al 45% en p\xe1ginas optimizadas en los primeros 90 d\xedas. Los resultados var\xedan por industria y punto de partida. Sitios con fricci\xf3n obvia suelen ver las mayores ganancias tempranas."},{question:"\xbfEn qu\xe9 se diferencia CRO del dise\xf1o web?",answer:"Dise\xf1o web construye o redise\xf1a tu sitio desde cero. CRO optimiza p\xe1ginas existentes mediante pruebas y mejoras UX para aumentar conversiones del tr\xe1fico que ya tienes. Muchos clientes hacen ambos."},{question:"\xbfHacen CRO en landing pages usadas para anuncios pagados?",answer:"S\xed. Landing pages de tr\xe1fico pagado suelen ser nuestros targets CRO de mayor prioridad porque incluso peque\xf1os lifts de conversi\xf3n reducen directamente tu costo por lead y mejoran ROAS."}]},"email-marketing":{metaTitle:"Agencia Email Marketing para Nutrici\xf3n B2B | KINEXIS Digital",metaDescription:"Email marketing y automatizaci\xf3n que nutre leads hasta convertirlos en clientes. Secuencias, campa\xf1as y crecimiento de lista ligados a pipeline. Programas desde $2,000/mes.",hero:{label:"Servicios Email Marketing",line1:"Email que mueve",line2:"prospectos hacia el s\xed.",subtitle:"Secuencias y campa\xf1as ligadas a d\xf3nde est\xe1 cada lead en tu pipeline.|No otro newsletter mensual que nadie lee."},answerBlock:"Los servicios email marketing incluyen estrategia de lista, flujos de automatizaci\xf3n, creaci\xf3n de campa\xf1as, segmentaci\xf3n, pruebas A/B y monitoreo de deliverability. Retainers parten en $2,000 a $5,000 al mes seg\xfan tama\xf1o de lista y complejidad de automatizaci\xf3n. Secuencias de bienvenida suelen lanzarse en 2 a 3 semanas.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Programas Email Generan Aperturas pero No Ingresos",intro:"Recolectar direcciones de email es f\xe1cil. Convertir esas direcciones en llamadas agendadas y deals cerrados requiere secuencias construidas alrededor de c\xf3mo tus compradores deciden realmente.",points:["Los newsletters salen mensualmente sin conexi\xf3n con d\xf3nde est\xe1 cada suscriptor en el proceso de compra.","Las automatizaciones se detienen despu\xe9s de un email de bienvenida en lugar de nutrir leads semanas o meses.","La segmentaci\xf3n es b\xe1sica o inexistente, y todos reciben el mismo mensaje sin importar inter\xe9s.","Problemas de deliverability mandan emails a spam porque las listas nunca se limpiaron ni calentaron bien."]},solution:{title:"Automatizaci\xf3n Email Mapeada a Tu Ciclo de Ventas",intro:"Construimos secuencias segmentadas que entregan el mensaje correcto en el momento correcto, desde el primer opt-in hasta retenci\xf3n post-compra.",points:["Secuencias de bienvenida, nutrici\xf3n y re-engagement ligadas a ofertas espec\xedficas y etapas del comprador.","Segmentaci\xf3n por fuente de lead, comportamiento y engagement para mantener mensajes relevantes.","Pruebas A/B en subject lines, horarios de env\xedo y CTAs para mejorar aperturas y clics con el tiempo.","Setup de deliverability incluyendo SPF, DKIM, DMARC e higiene de lista para proteger llegada a inbox."]},deliverables:{title:"Entregables Email Marketing",subtitle:"Estrategia, automatizaci\xf3n y campa\xf1as que impulsan pipeline, no solo aperturas.",items:[{title:"Estrategia Email y Calendario",description:"Plan de segmentaci\xf3n, frecuencia de env\xedo, temas de campa\xf1a y mapa de automatizaci\xf3n alineado a tu embudo."},{title:"Construcci\xf3n de Flujos de Automatizaci\xf3n",description:"Serie de bienvenida, secuencias de nutrici\xf3n, follow-ups de leads abandonados y flujos de retenci\xf3n post-venta."},{title:"Copy y Dise\xf1o de Campa\xf1as",description:"Copy de email, subject lines y plantillas responsive m\xf3vil para broadcasts y automatizaciones."},{title:"Segmentaci\xf3n y Gesti\xf3n de Lista",description:"Tags, segmentos y reglas de supresi\xf3n basadas en comportamiento, fuente y nivel de engagement."},{title:"Programa de Pruebas A/B",description:"Pruebas estructuradas en subject lines, preview text, CTAs y horarios de env\xedo con resultados documentados."},{title:"Reportes de Rendimiento y Deliverability",description:"Tasas de apertura, clics, conversiones, bajas y monitoreo de inbox placement mensualmente."}]},comparison:{title:"Email Marketing: Plataforma DIY vs. Programa Gestionado",subtitle:"Qu\xe9 obtienes con un programa email gestionado versus operarlo t\xfa mismo.",layout:"stacked",columns:[{header:"DIY en Mailchimp / HubSpot"},{header:"KINEXIS Email Marketing",highlight:!0}],rows:[{label:"Estrategia",values:["Broadcasts ad hoc","Plan de automatizaci\xf3n mapeado al embudo"]},{label:"Copy y dise\xf1o",values:["Equipo interno o plantillas","Copy profesional y plantillas custom"]},{label:"Segmentaci\xf3n",values:["Listas b\xe1sicas","Segmentos por comportamiento y fuente"]},{label:"Pruebas",values:["Raras o ninguna","Programa continuo de pruebas A/B"]},{label:"Deliverability",values:["A menudo descuidada","Monitoreo activo e higiene de lista"]},{label:"Inversi\xf3n de tiempo",values:["5 a 10 horas/semana internamente","Ejecuci\xf3n completamente gestionada"]}]},extraFaqs:[{question:"\xbfCon qu\xe9 plataformas email trabajan?",answer:"Trabajamos con HubSpot, ActiveCampaign, Klaviyo, Mailchimp y ConvertKit seg\xfan tu tipo de negocio y necesidades de integraci\xf3n. Recomendamos la mejor opci\xf3n en tu llamada estrat\xe9gica."},{question:"\xbfCu\xe1nto cuesta la gesti\xf3n de email marketing?",answer:"Retainers van de $2,000 a $5,000 al mes seg\xfan tama\xf1o de lista, cantidad de automatizaciones y frecuencia de campa\xf1as. Proyectos con setup pesado y nuevas automatizaciones pueden tener tarifa \xfanica de onboarding."},{question:"\xbfQu\xe9 tan r\xe1pido pueden lanzar automatizaciones email?",answer:"Secuencias de bienvenida y nutrici\xf3n b\xe1sica suelen lanzarse en 2 a 3 semanas. Automatizaci\xf3n completa de embudo con segmentaci\xf3n y m\xfaltiples secuencias toma 4 a 6 semanas."},{question:"\xbfPueden mejorar nuestra deliverability email?",answer:"S\xed. Auditamos registros SPF, DKIM y DMARC, limpiamos tu lista, configuramos calentamiento correcto para dominios nuevos y monitoreamos tasas de quejas spam. La mayor\xeda de problemas de deliverability se resuelve en 2 a 4 semanas de correcciones."}]},"content-marketing":{metaTitle:"Agencia Marketing de Contenidos para Crecimiento B2B | KINEXIS Digital",metaDescription:"Marketing de contenidos que posiciona en b\xfasqueda y genera confianza con compradores. Estrategia, art\xedculos, gu\xedas y distribuci\xf3n desde $2,500/mes. Primer contenido live en 3 a 4 semanas.",hero:{label:"Servicios Marketing de Contenidos",line1:"Contenido que responde",line2:"lo que buscan antes de llamar.",subtitle:"Posts, gu\xedas y casos mapeados a keywords y etapas de compra.|Escritos para posicionar, generar confianza y llevar a tu oferta."},answerBlock:"Los servicios de marketing de contenidos incluyen estrategia de contenido, planificaci\xf3n de temas basada en keywords, art\xedculos de blog, gu\xedas, casos de estudio y distribuci\xf3n en b\xfasqueda y social. Retainers parten en $2,500 a $6,000 al mes para 4 a 8 piezas mensuales. El primer contenido publicado suele salir live en 3 a 4 semanas desde kickoff.",problem:{title:"Por Qu\xe9 la Mayor\xeda del Marketing de Contenidos Produce Posts pero No Pipeline",intro:"Publicar art\xedculos de blog sin estrategia crea ruido, no autoridad. El contenido solo impulsa ingresos cuando apunta a las preguntas que tus compradores hacen antes de contactarte.",points:["Los temas se eligen al azar en lugar de mapearse a intenci\xf3n de keyword y etapas del comprador.","El contenido suena a relleno gen\xe9rico sin insight original, datos ni prueba social.","Los posts se publican pero nunca se promocionan, enlazan internamente ni actualizan por frescura.","No hay conexi\xf3n entre temas de contenido y las p\xe1ginas de servicio u ofertas que generan ingresos."]},solution:{title:"Contenido que Posiciona, Educa y Convierte",intro:"Planificamos contenido alrededor de keywords y preguntas que buscan tus compradores, luego escribimos piezas que generan confianza y enlazan naturalmente a tus p\xe1ginas de conversi\xf3n.",points:["Clusters de temas organizados alrededor de servicios core y preguntas del comprador en cada etapa.","Redacci\xf3n informada por SEO con investigaci\xf3n original, ejemplos de clientes y takeaways accionables.","Estrategia de interlinking que pasa autoridad a tus money pages.","Ciclos de refresh que actualizan top performers y retiran posts de bajo rendimiento."]},deliverables:{title:"Entregables Marketing de Contenidos",subtitle:"De estrategia a publicaci\xf3n, construido para atraer y convertir compradores ideales.",items:[{title:"Estrategia de Contenido y Calendario Editorial",description:"Clusters de temas, keywords target, calendario de publicaci\xf3n y tipos de contenido mapeados a tu embudo."},{title:"Art\xedculos de Blog y Posts",description:"Art\xedculos SEO de 1,500 a 2,500 palabras con \xe1ngulos originales, datos y enlaces internos."},{title:"Gu\xedas e Imanes de Leads",description:"Recursos descargables dise\xf1ados para capturar emails y posicionar tu marca como experta."},{title:"Casos de Estudio y Contenido de Prueba Social",description:"Historias de \xe9xito de clientes formateadas para sitio web, equipo de ventas y secuencias email de nutrici\xf3n."},{title:"Plan de Distribuci\xf3n de Contenido",description:"Compartir en social, promoci\xf3n email y outreach para amplificar cada pieza m\xe1s all\xe1 de b\xfasqueda org\xe1nica."},{title:"Reportes de Rendimiento",description:"Tr\xe1fico, posiciones, engagement y atribuci\xf3n de leads por pieza de contenido mensualmente."}]},comparison:{title:"Marketing de Contenidos: Freelancer vs. Programa Agencia",subtitle:"Compara contratar un redactor freelance contra un programa completo de content marketing.",layout:"stacked",columns:[{header:"Redactor Freelance"},{header:"KINEXIS Marketing de Contenidos",highlight:!0}],rows:[{label:"Estrategia",values:["T\xfa provees temas","Plan editorial mapeado a keywords y embudo"]},{label:"Integraci\xf3n SEO",values:["B\xe1sica o ninguna","Integrada en cada pieza de planificaci\xf3n a publicaci\xf3n"]},{label:"Tipos de contenido",values:["Solo art\xedculos de blog","Posts, gu\xedas, casos de estudio e imanes de leads"]},{label:"Interlinking interno",values:["No incluido","Flujo de autoridad hacia p\xe1ginas de servicio y landing"]},{label:"Distribuci\xf3n",values:["Publicar y esperar","Promoci\xf3n en b\xfasqueda, email y social"]},{label:"Inversi\xf3n mensual",values:["$500 a $1,500 por pieza","$2,500 a $6,000 por 4 a 8 piezas"]}]},extraFaqs:[{question:"\xbfCu\xe1ntas piezas de contenido producen al mes?",answer:"La mayor\xeda de retainers incluyen 4 a 8 piezas al mes seg\xfan longitud y tipo. Un mix t\xedpico es 3 a 4 art\xedculos de blog m\xe1s una gu\xeda o caso de estudio. Ajustamos volumen seg\xfan metas y presupuesto."},{question:"\xbfEscriben contenido con fines SEO?",answer:"S\xed. Cada pieza empieza con investigaci\xf3n de keywords y an\xe1lisis de intenci\xf3n de b\xfasqueda. Marketing de contenidos y SEO trabajan juntos en nuestros programas, aunque servicios SEO dedicados agregan optimizaci\xf3n t\xe9cnica y link building encima."},{question:"\xbfCu\xe1nto tarda el marketing de contenidos en generar tr\xe1fico?",answer:"Art\xedculos nuevos suelen empezar a posicionar en 60 a 90 d\xedas. El crecimiento compuesto de tr\xe1fico se construye en 6 a 12 meses conforme crece tu biblioteca de contenido y autoridad de dominio. Imanes de leads pueden generar emails de inmediato mediante promoci\xf3n."},{question:"\xbfPueden escribir contenido para mi industria espec\xedfica?",answer:"S\xed. Trabajamos en home services, healthcare, servicios profesionales, SaaS y e-commerce. Investigamos tu mercado, entrevistamos a tu equipo y usamos ejemplos de clientes para producir contenido que suena escrito por alguien de adentro."}]},"social-media":{metaTitle:"Agencia Marketing en Redes Sociales para Marcas B2B | KINEXIS Digital",metaDescription:"Gesti\xf3n de redes sociales que construye visibilidad de marca e impulsa tr\xe1fico al sitio web. Creaci\xf3n de contenido, publicaci\xf3n y community management desde $1,500/mes.",hero:{label:"Marketing en Redes Sociales",line1:"Social que apoya",line2:"el resto de tu marketing.",subtitle:"Publicaci\xf3n constante, creativos on-brand y respuestas en comunidad.|No posts promocionales aleatorios sin conexi\xf3n con ingresos."},answerBlock:"El marketing en redes sociales incluye estrategia de plataforma, creaci\xf3n de contenido, calendarios de publicaci\xf3n, community management y reportes de rendimiento para LinkedIn, Instagram, Facebook y X. La gesti\xf3n parte en $1,500 a $4,000 al mes seg\xfan plataformas y frecuencia de publicaci\xf3n. Calendarios de contenido quedan live en 2 semanas desde kickoff.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Cuentas Sociales Empresariales No Avanzan",intro:"Publicar de forma inconsistente sin estrategia crea un perfil que parece inactivo y da\xf1a confianza en lugar de construirla. Las redes sociales solo funcionan cuando conectan con metas de negocio.",points:["Las cuentas publican espor\xe1dicamente con contenido promocional que los seguidores ignoran.","No hay pilares de contenido ni gu\xedas de voz de marca, y los posts se sienten aleatorios y off-brand.","El engagement se trata como m\xe9trica vanidosa sin v\xednculo a tr\xe1fico web o leads.","El community management se ignora, y comentarios y mensajes quedan sin respuesta d\xedas."]},solution:{title:"Redes Sociales que Apoyan Tus Metas de Ingresos",intro:"Construimos un sistema de contenido con pilares claros, publicaci\xf3n consistente y CTAs que llevan seguidores a tu sitio web, ofertas e imanes de leads.",points:["Estrategia de plataforma enfocada en d\xf3nde pasan tiempo tus compradores, no en todas las redes a la vez.","Pilares de contenido alineados a tus servicios, expertise y preguntas del comprador.","Calendario de publicaci\xf3n consistente con gr\xe1ficos, captions y hashtags optimizados por plataforma.","Community management que responde comentarios y DMs en menos de 24 horas."]},deliverables:{title:"Entregables Gesti\xf3n de Redes Sociales",subtitle:"Presencia social consistente y on-brand gestionada de punta a punta.",items:[{title:"Estrategia de Plataforma y Pilares de Contenido",description:"Selecci\xf3n de canales, frecuencia de publicaci\xf3n, temas de contenido y gu\xedas de voz de marca."},{title:"Creaci\xf3n de Contenido y Dise\xf1o",description:"Gr\xe1ficos, carruseles, copy corto y clips de video adaptados a cada plataforma."},{title:"Programaci\xf3n y Publicaci\xf3n",description:"Calendario de publicaci\xf3n consistente con horarios \xf3ptimos y formato espec\xedfico por plataforma."},{title:"Community Management",description:"Respuestas a comentarios, manejo de DMs e interacci\xf3n con cuentas relevantes de tu sector."},{title:"CTAs de Social a Sitio Web",description:"Enlaces en bio, CTAs en stories y copy de posts que llevan tr\xe1fico a landing pages y ofertas."},{title:"Reporte Anal\xedtico Mensual",description:"Crecimiento de seguidores, alcance, engagement, clics y desglose de contenido top performer."}]},comparison:{title:"Redes Sociales: In-House vs. Gestionado",subtitle:"Compara contratar internamente contra un programa gestionado de redes sociales.",layout:"ledger",columns:[{header:"Social Manager In-House"},{header:"KINEXIS Redes Sociales",highlight:!0}],rows:[{label:"Costo mensual",values:["$4,000 a $6,000 de salario m\xe1s herramientas","$1,500 a $4,000 todo incluido"]},{label:"Volumen de contenido",values:["Limitado por una persona","Equipo de dise\xf1o, copy y programaci\xf3n"]},{label:"Cobertura de plataformas",values:["1 a 2 plataformas bien","Multi-plataforma con contenido espec\xedfico por canal"]},{label:"Estrategia",values:["A menudo publicaci\xf3n reactiva","Pilares de contenido ligados a metas de negocio"]},{label:"Community management",values:["Solo horario laboral","Monitoreo y respuesta diaria"]},{label:"Tiempo para arrancar",values:["30 a 60 d\xedas para contratar","2 semanas para calendario live"]}]},extraFaqs:[{question:"\xbfQu\xe9 plataformas de redes sociales gestionan?",answer:"LinkedIn, Instagram, Facebook y X. Recomendamos enfocarse en 2 a 3 plataformas donde tus compradores est\xe1n activos en lugar de dispersarse en todas las redes."},{question:"\xbfEn qu\xe9 se diferencia gesti\xf3n de redes sociales de Meta Ads?",answer:"Gesti\xf3n de redes sociales es contenido org\xe1nico, publicaci\xf3n y engagement comunitario. Meta Ads es publicidad pagada en Facebook e Instagram. Funcionan mejor juntos pero cumplen roles distintos en tu programa de marketing."},{question:"\xbfCrean gr\xe1ficos y videos para posts sociales?",answer:"S\xed. Creaci\xf3n de contenido incluyendo gr\xe1ficos, carruseles y clips de video corto est\xe1 incluida en nuestros paquetes de gesti\xf3n. Producci\xf3n de video largo se maneja a trav\xe9s de nuestro servicio de video marketing."},{question:"\xbfLas redes sociales realmente generan leads para B2B?",answer:"Las redes sociales rara vez son canal directo de leads para B2B, pero construyen confianza e impulsan tr\xe1fico a tu contenido, ofertas y sitio web. Medimos clics y atribuimos leads que originan en touchpoints sociales."}]},"video-marketing":{metaTitle:"Agencia Marketing de Video para Marcas B2B | KINEXIS Digital",metaDescription:"Marketing de video para anuncios, social y conversi\xf3n web. Guion, producci\xf3n y edici\xf3n desde $3,000 por proyecto o retainer $2,500/mes.",hero:{label:"Servicios Marketing de Video",line1:"Video hecho para",line2:"donde realmente se publica.",subtitle:"Anuncios, redes y web con un mensaje claro por pieza.|De gui\xf3n a edici\xf3n, formateado para cada plataforma."},answerBlock:"Los servicios de video marketing incluyen desarrollo de concepto, guion, coordinaci\xf3n de producci\xf3n, edici\xf3n y planificaci\xf3n de distribuci\xf3n para anuncios, social y web. Proyectos parten en $3,000 para paquetes short-form. Retainers mensuales desde $2,500 cubren contenido de video continuo. Entrega t\xedpica: 2 a 4 semanas por proyecto.",problem:{title:"Por Qu\xe9 la Mayor\xeda del Video Empresarial Rinde Poco",intro:"El video es el formato de mayor engagement en cada plataforma, pero la mayor\xeda de videos empresariales son muy largos, muy gen\xe9ricos o producidos sin meta clara.",points:["Los videos intentan explicar todo en lugar de hacer un punto claro por pieza.","La calidad de producci\xf3n es inconsistente, da\xf1ando percepci\xf3n de marca en anuncios y social.","Sin plan de distribuci\xf3n, los videos quedan en YouTube sin promoci\xf3n en anuncios o social.","Los creativos de anuncio se estancan porque nuevas variaciones de video son caras o lentas de producir."]},solution:{title:"Contenido Video Construido para Cada Plataforma y Prop\xf3sito",intro:"Escribimos y producimos videos dise\xf1ados para d\xf3nde vivir\xe1n, ya sea un anuncio de 15 segundos, clip social de 60 segundos o explainer de 3 minutos en tu homepage.",points:["Formatos espec\xedficos por plataforma: vertical para social, horizontal para YouTube, cortes cortos para anuncios.","Guiones enfocados en un mensaje por video con CTA claro al final.","Flujos de producci\xf3n eficientes que entregan m\xfaltiples cortes desde una sola grabaci\xf3n.","Planificaci\xf3n de distribuci\xf3n para que cada video llegue a anuncios, social, email y sitio web."]},deliverables:{title:"Entregables Marketing de Video",subtitle:"De concepto a edici\xf3n final, optimizado para tus canales.",items:[{title:"Estrategia de Video y Plan de Contenido",description:"Tipos de video, mapeo de plataformas, temas de mensaje y calendario de producci\xf3n."},{title:"Guion y Storyboard",description:"Guiones, shot lists y storyboards aprobados antes de iniciar producci\xf3n."},{title:"Coordinaci\xf3n de Producci\xf3n",description:"Grabaci\xf3n on-location o remota con iluminaci\xf3n, audio y direcci\xf3n profesional."},{title:"Edici\xf3n y Post-Producci\xf3n",description:"Cortes, subt\xedtulos, gr\xe1ficos, licencias de m\xfasica y color grading para archivos finales pulidos."},{title:"Exports Optimizados por Plataforma",description:"M\xfaltiples aspect ratios y duraciones formateadas para anuncios, social, web y email."},{title:"Setup de Seguimiento de Rendimiento",description:"Views, engagement, clics y rendimiento de anuncios ligados a cada asset de video."}]},comparison:{title:"Video Marketing: Proyecto \xdanico vs. Programa Continuo",subtitle:"Compara un proyecto de video \xfanico contra un programa mensual de contenido video.",layout:"stacked",columns:[{header:"Video Explicativo \xdanico"},{header:"Retainer KINEXIS Video",highlight:!0}],rows:[{label:"Inversi\xf3n",values:["$5,000 a $15,000 una vez","$2,500 a $6,000/mes continuo"]},{label:"Volumen de contenido",values:["1 video","4 a 8 piezas al mes"]},{label:"Refresh de creativos de anuncio",values:["Se estancan en 4 a 6 semanas","Nuevos cortes de anuncio cada mes"]},{label:"Cobertura de plataformas",values:["Un formato","Exports multi-formato por grabaci\xf3n"]},{label:"Entrega",values:["6 a 8 semanas","2 a 4 semanas por batch"]},{label:"Ideal para",values:["Video hero de sitio web","Programas activos de anuncios y social"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta la producci\xf3n de video?",answer:"Paquetes short-form para social parten en $3,000 por proyecto. Videos explicativos van de $5,000 a $12,000. Retainers mensuales desde $2,500 entregan 4 a 8 piezas. Cotizamos seg\xfan duraci\xf3n, complejidad y cantidad de entregables."},{question:"\xbfNecesito salir en c\xe1mara?",answer:"No necesariamente. Producimos videos con founder, entrevistas de equipo, animaci\xf3n y estilo b-roll seg\xfan lo que encaje con tu marca. Salir en c\xe1mara genera confianza m\xe1s r\xe1pido para negocios de servicios, pero no es obligatorio."},{question:"\xbfPueden crear video ads para Meta y Google?",answer:"S\xed. Producimos cortes de video espec\xedficos para anuncios en formatos y duraciones que requiere cada plataforma. Esto se integra directamente con nuestros servicios de gesti\xf3n Meta Ads y Google Ads."},{question:"\xbfCu\xe1nto tarda la producci\xf3n de video?",answer:"La mayor\xeda de proyectos entrega en 2 a 4 semanas desde aprobaci\xf3n de guion hasta archivos finales. Clientes con retainer tienen calendario de producci\xf3n continuo con contenido nuevo cada mes."}]},branding:{metaTitle:"Agencia de Branding para Empresas B2B | KINEXIS Digital",metaDescription:"Servicios de branding incluyendo posicionamiento, identidad visual y mensaje para empresas B2B. Estrategia de marca y dise\xf1o desde $8,000 a $25,000.",hero:{label:"Servicios de Branding",line1:"Una marca que reconocen",line2:"antes de leer la letra chica.",subtitle:"Posicionamiento, identidad visual y mensaje, documentados.|Para que sitio, anuncios y ventas suenen como una sola empresa."},answerBlock:"Los servicios de branding incluyen posicionamiento de mercado, estrategia de marca, dise\xf1o de logo, sistemas de identidad visual, marcos de mensaje y gu\xedas de marca. Proyectos van de $8,000 para refrescos de identidad enfocados a $25,000+ para estrategia y dise\xf1o de marca completa. Entrega t\xedpica: 6 a 10 semanas.",problem:{title:"Por Qu\xe9 un Branding D\xe9bil Te Cuesta Clientes",intro:"Si tu marca se ve inconsistente o tu mensaje no es claro, los compradores eligen al competidor que parece m\xe1s establecido. El branding no es vanidad, es la base sobre la que se construye todo canal de marketing.",points:["Logo, colores y tipograf\xedas var\xedan entre sitio web, anuncios y perfiles sociales.","El mensaje intenta atraer a todos y no conecta con nadie en particular.","No hay gu\xedas de marca documentadas, y cada pieza nueva de contenido se ve distinta.","El posicionamiento es vago, y cuesta a prospectos entender por qu\xe9 deber\xedan elegirte."]},solution:{title:"Estrategia de Marca que Facilita el Marketing",intro:"Aclaramos a qui\xe9n sirves, qu\xe9 te diferencia y c\xf3mo te ves y suenas, luego lo documentamos para que tu equipo y cada agencia partner se mantengan alineados.",points:["Workshops de posicionamiento que definen cliente ideal, diferenciadores y \xe1ngulo competitivo.","Dise\xf1o de identidad visual incluyendo logo, paleta de color, tipograf\xeda y sistema de dise\xf1o.","Marco de mensaje con taglines, propuestas de valor y gu\xedas de tono de voz.","Documento de gu\xedas de marca que tu equipo y partners consultan para cada asset nuevo."]},deliverables:{title:"Entregables del Proyecto de Branding",subtitle:"Estrategia, dise\xf1o y documentaci\xf3n para una presencia de marca coherente.",items:[{title:"Estrategia de Marca y Posicionamiento",description:"An\xe1lisis de mercado, revisi\xf3n competitiva, perfil de cliente ideal y statement de posicionamiento."},{title:"Dise\xf1o de Logo e Identidad Visual",description:"Logos primario y secundario, paleta de color, tipograf\xeda y estilo de iconograf\xeda."},{title:"Marco de Mensaje",description:"Tagline, elevator pitch, propuestas de valor y gu\xedas de tono de voz."},{title:"Documento de Gu\xedas de Marca",description:"Reglas de uso para logo, colores, fuentes, im\xe1genes y mensaje en todos los canales."},{title:"Plantillas de Collateral Empresarial",description:"Decks de presentaci\xf3n, plantillas de propuestas, assets de perfil social y firmas de email."},{title:"Soporte de Lanzamiento de Marca",description:"Plan de rollout para actualizar sitio web, perfiles sociales y materiales de marketing."}]},comparison:{title:"Branding: Logo en Fiverr vs. Estrategia de Marca Completa",subtitle:"Qu\xe9 obtienes con un proyecto estrat\xe9gico de branding versus comprar solo un logo.",layout:"contrast",columns:[{header:"Servicio Solo Logo"},{header:"KINEXIS Branding",highlight:!0}],rows:[{label:"Estrategia",values:["Ninguna","Posicionamiento, mensaje y an\xe1lisis competitivo"]},{label:"Entregables",values:["Un archivo de logo","Sistema de identidad completo y gu\xedas"]},{label:"Mensaje",values:["No incluido","Tagline, value props y tono de voz"]},{label:"Consistencia",values:["Sin reglas de uso","Gu\xedas documentadas para todos los canales"]},{label:"Inversi\xf3n",values:["$50 a $500","$8,000 a $25,000"]},{label:"Impacto en marketing",values:["Cambio cosm\xe9tico","Base para todos los canales de marketing"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta un proyecto de branding?",answer:"Refrescos de identidad parten en $8,000. Estrategia de marca completa con posicionamiento, mensaje e identidad visual va de $15,000 a $25,000. Definimos alcance seg\xfan entregables y timeline en discovery."},{question:"\xbfCu\xe1nto tarda un proyecto de branding?",answer:"La mayor\xeda de proyectos entrega en 6 a 10 semanas. Estrategia y posicionamiento toman 2 a 3 semanas, exploraci\xf3n de dise\xf1o 3 a 4 semanas, y gu\xedas y collateral 1 a 2 semanas."},{question:"\xbfNecesito branding antes de empezar marketing?",answer:"Puedes empezar marketing sin rebrand completo, pero posicionamiento claro y visuales consistentes hacen que cada otro canal rinda m\xe1s. A menudo corremos branding y dise\xf1o web en paralelo."},{question:"\xbfSer\xe9 due\xf1o de todos los archivos de marca y fuentes?",answer:"S\xed. Recibes todos los archivos de logo, assets de dise\xf1o, licencias de fuentes y el documento de gu\xedas de marca. Todo es tuyo para uso interno y con cualquier agencia partner."}]},analytics:{metaTitle:"Agencia Anal\xedtica de Marketing para Equipos B2B | KINEXIS Digital",metaDescription:"Anal\xedtica y reportes de marketing que conectan campa\xf1as con ingresos. Setup GA4, dashboards y atribuci\xf3n desde $1,500/mes.",hero:{label:"Servicios Anal\xedtica de Marketing",line1:"Reportes que te dicen",line2:"d\xf3nde invertir despu\xe9s.",subtitle:"GA4, CRM y dashboards centrados en leads e ingresos.|No otro export lleno de impresiones que nadie usa."},answerBlock:"Los servicios de anal\xedtica de marketing incluyen setup GA4, tracking de conversiones, integraci\xf3n CRM, dashboards custom y reportes mensuales en SEO, anuncios pagados, email y social. Retainers parten en $1,500 a $3,500 al mes. Dashboards suelen quedar live en 2 a 3 semanas.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Reportes de Marketing No Ayudan a Decidir",intro:"Dashboards llenos de impresiones y page views se ven productivos pero no dicen si el marketing genera ingresos. Malos datos llevan a malas decisiones de presupuesto.",points:["GA4 est\xe1 instalado pero eventos, conversiones y audiencias est\xe1n mal configurados o faltan.","Datos de plataformas de anuncios y leads en CRM nunca se conectan, y el ROAS real es desconocido.","Los reportes muestran tr\xe1fico por canal sin ligar visitas a leads calificados o deals cerrados.","Distintos miembros del equipo miran herramientas distintas y llegan a conclusiones distintas."]},solution:{title:"Anal\xedtica que Conecta Campa\xf1as con Ingresos",intro:"Corregimos tu base de tracking, construimos dashboards alrededor de resultados de negocio y reportamos mensualmente qu\xe9 funciona y qu\xe9 necesita cambiar.",points:["Setup GA4 y tag manager con eventos, conversiones y definiciones de audiencia correctas.","Integraci\xf3n CRM y plataformas de anuncios para atribuir leads a canal y campa\xf1a de origen.","Dashboards custom en GA4, Looker Studio o tu herramienta preferida enfocados en KPIs accionables.","Reportes mensuales con insights y recomendaciones, no solo capturas exportadas."]},deliverables:{title:"Entregables Anal\xedtica de Marketing",subtitle:"Tracking, dashboards y reportes construidos alrededor de m\xe9tricas de ingresos.",items:[{title:"Auditor\xeda Anal\xedtica y Plan de Correcci\xf3n",description:"Revisi\xf3n de GA4, tags, p\xedxeles, integraci\xf3n CRM y definiciones de conversi\xf3n con correcciones priorizadas."},{title:"Setup GA4 y Tag Manager",description:"Event tracking, conversion actions, enhanced measurement y configuraci\xf3n cross-domain."},{title:"Integraci\xf3n CRM y Plataformas de Anuncios",description:"Atribuci\xf3n de fuente de leads conectando HubSpot, Salesforce o tu CRM con datos de anuncios y org\xe1nico."},{title:"Construcci\xf3n de Dashboard Custom",description:"Dashboards Looker Studio o GA4 mostrando tr\xe1fico, leads, CPL, ROAS y pipeline por canal."},{title:"Reporte Mensual de Rendimiento",description:"Desglose canal por canal con tendencias, anomal\xedas y recomendaciones accionables."},{title:"Revisi\xf3n Estrat\xe9gica Trimestral",description:"An\xe1lisis profundo de datos de atribuci\xf3n con recomendaciones de reasignaci\xf3n de presupuesto para el trimestre siguiente."}]},comparison:{title:"Anal\xedtica de Marketing: GA4 Default vs. Programa Gestionado",subtitle:"Qu\xe9 cambia cuando especialistas configuran y gestionan tu anal\xedtica.",layout:"ledger",columns:[{header:"GA4 Default / Setup DIY"},{header:"KINEXIS Anal\xedtica",highlight:!0}],rows:[{label:"Tracking de conversiones",values:["Page views y eventos b\xe1sicos","Eventos de leads calificados e ingresos"]},{label:"Integraci\xf3n CRM",values:["Manual o ninguna","Atribuci\xf3n de fuente automatizada"]},{label:"Dashboards",values:["Reportes gen\xe9ricos GA4","Dashboards KPI custom"]},{label:"Vista cross-channel",values:["Datos aislados por plataforma","Vista unificada de rendimiento por canal"]},{label:"Cadencia de reportes",values:["Ad hoc cuando alguien pregunta","Mensual con recomendaciones"]},{label:"Calidad de decisiones",values:["Suposiciones en asignaci\xf3n de presupuesto","Inversi\xf3n por canal respaldada en datos"]}]},extraFaqs:[{question:"\xbfCon qu\xe9 herramientas anal\xedticas trabajan?",answer:"GA4, Google Tag Manager, Looker Studio, HubSpot, Salesforce y anal\xedtica nativa de plataformas de anuncios. Construimos dashboards en la herramienta que tu equipo ya usa o recomendamos la mejor opci\xf3n."},{question:"\xbfCu\xe1nto cuesta la gesti\xf3n de anal\xedtica de marketing?",answer:"Retainers van de $1,500 a $3,500 al mes seg\xfan cantidad de canales, integraciones y complejidad de reportes. Proyectos \xfanicos de setup GA4 y dashboards parten en $3,000."},{question:"\xbfPueden corregir nuestro setup GA4 existente?",answer:"S\xed. La mayor\xeda de cuentas que auditamos tienen eventos faltantes, conversiones duplicadas o conexiones CRM rotas. Normalmente resolvemos problemas core de tracking en 2 a 3 semanas."},{question:"\xbfReportan ROI y ROAS?",answer:"S\xed, cuando la integraci\xf3n CRM est\xe1 en su lugar. Reportamos costo por lead, costo por adquisici\xf3n, ROAS por canal y valor de pipeline atribuido a campa\xf1as de marketing."}]},"growth-consulting":{metaTitle:"Consultor\xeda de Crecimiento para Estrategia B2B | KINEXIS Digital",metaDescription:"Consultor\xeda de crecimiento para negocios que necesitan estrategia de marketing antes de ejecutar. Auditor\xedas de canal, roadmaps y planificaci\xf3n trimestral desde $3,000/mes.",hero:{label:"Servicios Consultor\xeda de Crecimiento",line1:"Sabe qu\xe9 hacer",line2:"antes de volver a gastar.",subtitle:"Auditor\xeda de marketing, prioridades por canal y roadmap con presupuesto y KPIs|que tu equipo o el nuestro puede ejecutar."},answerBlock:"La consultor\xeda de crecimiento incluye auditor\xedas de marketing, an\xe1lisis competitivo, estrategia de canal, planificaci\xf3n de presupuesto y roadmaps trimestrales. Engagements parten en $3,000 a $6,000 al mes en modalidad advisory o $5,000 a $15,000 por entregables de estrategia por proyecto. Auditor\xeda inicial y roadmap se entregan en 3 a 4 semanas.",problem:{title:"Por Qu\xe9 los Negocios Gastan en Marketing Sin Estrategia",intro:"T\xe1cticas sin estrategia queman presupuesto r\xe1pido. La mayor\xeda de negocios sabe que necesita marketing pero carece de plan claro sobre qu\xe9 canales priorizar, cu\xe1nto invertir y qu\xe9 resultados esperar.",points:["El presupuesto se reparte en demasiados canales sin inversi\xf3n suficiente en ninguno para funcionar.","Relaciones pasadas con agencias terminaron sin aprendizajes claros ni estrategia documentada.","Equipos internos ejecutan tareas pero nadie es due\xf1o del plan de crecimiento general.","Metas de ingresos se fijan sin plan de marketing que las respalde de forma realista."]},solution:{title:"Un Roadmap de Crecimiento Basado en Tus Datos y Mercado",intro:"Auditamos lo que tienes, analizamos tu mercado competitivo y entregamos un plan priorizado con recomendaciones de canal, asignaci\xf3n de presupuesto y metas KPI.",points:["Auditor\xeda completa de marketing cubriendo sitio web, anuncios, SEO, email y setup anal\xedtico.","An\xe1lisis competitivo mostrando d\xf3nde invierten rivales y d\xf3nde existen brechas en tu mercado.","Estrategia de canal con niveles de inversi\xf3n recomendados y timelines esperados por cada uno.","Roadmap trimestral con hitos, KPIs y puntos de decisi\xf3n para escalar o pivotar."]},deliverables:{title:"Entregables Consultor\xeda de Crecimiento",subtitle:"Estrategia y planificaci\xf3n que convierten gasto de marketing en programa coordinado.",items:[{title:"Auditor\xeda de Marketing y Scorecard",description:"Evaluaci\xf3n de cada canal activo con scores de tracking, creativos, targeting y conversi\xf3n."},{title:"An\xe1lisis de Mercado Competitivo",description:"Revisi\xf3n de posicionamiento de competidores, se\xf1ales de ad spend, estrategia de contenido y brechas de keywords."},{title:"Estrategia de Canal y Plan de Presupuesto",description:"Mix de canales recomendado, asignaci\xf3n mensual de presupuesto y CPL y timeline esperados por canal."},{title:"Documento Roadmap de Crecimiento",description:"Plan trimestral con prioridades, hitos, KPIs y dependencias entre canales."},{title:"Sesiones Estrat\xe9gicas Trimestrales",description:"Sesiones de trabajo en vivo para revisar rendimiento, ajustar prioridades y planificar el trimestre siguiente."},{title:"Handoff de Ejecuci\xf3n o Rollout Gestionado",description:"Opci\xf3n de ejecutar el plan con nuestro equipo o entregarlo a tu equipo interno con specs claras."}]},comparison:{title:"Consultor\xeda de Crecimiento vs. Saltar a Ejecuci\xf3n",subtitle:"Por qu\xe9 estrategia antes de t\xe1cticas ahorra presupuesto y acelera resultados.",layout:"stacked",columns:[{header:"Empezar Anuncios de Inmediato"},{header:"KINEXIS Consultor\xeda de Crecimiento",highlight:!0}],rows:[{label:"Inversi\xf3n inicial",values:["$0 estrategia, $5K+/mes en anuncios","$3K a $6K/mes advisory"]},{label:"Selecci\xf3n de canal",values:["Adivinar o copiar competidores","Recomendaci\xf3n respaldada en datos"]},{label:"Eficiencia de presupuesto",values:["30% a 50% desperdiciado en primeros 90 d\xedas","Gasto priorizado desde el d\xeda uno"]},{label:"Preparaci\xf3n de tracking",values:["Se corrige cuando aparecen problemas","Integrado al plan antes del lanzamiento"]},{label:"Timeline de resultados",values:["Impredecible","Hitos realistas por canal"]},{label:"Ideal para",values:["Oferta probada, listo para escalar","Estrategia poco clara o fracasos previos"]}]},extraFaqs:[{question:"\xbfEn qu\xe9 se diferencia consultor\xeda de crecimiento de sus otros servicios?",answer:"Consultor\xeda de crecimiento es estrategia y planificaci\xf3n. Nuestros otros servicios son ejecuci\xf3n. Muchos clientes empiezan con consultor\xeda para construir el roadmap, luego nos contratan a nosotros o a su equipo interno para SEO, anuncios, dise\xf1o web y otros canales."},{question:"\xbfEjecutan la estrategia o solo asesoran?",answer:"Ambas opciones est\xe1n disponibles. Engagements advisory dan a tu equipo el plan y gu\xeda trimestral. Engagements gestionados agregan nuestro equipo de ejecuci\xf3n operando los canales recomendados en tu roadmap."},{question:"\xbfCu\xe1nto cuesta la consultor\xeda de crecimiento?",answer:"Retainers advisory van de $3,000 a $6,000 al mes. Entregables de estrategia por proyecto van de $5,000 a $15,000 por auditor\xeda, an\xe1lisis competitivo y documento roadmap."},{question:"\xbfCu\xe1nto dura un engagement de consultor\xeda de crecimiento?",answer:"La mayor\xeda de clientes advisory trabaja con nosotros 3 a 6 meses para construir y refinar el plan, luego transiciona a ejecuci\xf3n. Algunos nos retienen trimestralmente para supervisi\xf3n estrat\xe9gica continua."}]},funnels:{metaTitle:"Agencia de Embudos y CRO | Sistemas de Conversi\xf3n | KINEXIS Digital",metaDescription:"Embudos y optimizaci\xf3n de conversi\xf3n en un solo sistema de ingresos. Landing pages, automatizaci\xf3n email, pruebas A/B y UX. Proyectos desde $5,000; programas desde $2,500/mes.",hero:{label:"Embudos y Optimizaci\xf3n de Conversi\xf3n",line1:"Capta y nutre leads",line2:"y sigue probando qu\xe9 convierte.",subtitle:"Landing pages, automatizaci\xf3n de email, retargeting y tests A/B|como un sistema desde el primer clic hasta la reserva."},answerBlock:"Servicios de embudos y CRO incluyen estrategia de embudo, dise\xf1o de landing pages, imanes de leads, automatizaci\xf3n email, retargeting, an\xe1lisis de heatmaps y pruebas A/B estructuradas. Builds desde $5,000 a $15,000; programas CRO desde $2,500 al mes. La mayor\xeda de sistemas lanzan en 4 a 8 semanas con optimizaci\xf3n continua.",problem:{title:"Por Qu\xe9 la Mayor\xeda de Negocios Pierden Ingresos en Cada Etapa",intro:"Una landing page sola no es un embudo, y tr\xe1fico sin optimizaci\xf3n es desperdicio costoso. La mayor\xeda pierde leads entre el formulario y la reserva, y nunca ejecuta las pruebas que mostrar\xedan por qu\xe9.",points:["Los leads se registran pero no reciben follow-up m\xe1s all\xe1 de una thank-you page gen\xe9rica.","Las landing pages convierten al 1% al 2% porque el mensaje no coincide con el anuncio u oferta.","Sin framework de A/B testing, las suposiciones reemplazan mejoras basadas en datos.","Retargeting y nutrici\xf3n se detienen pronto, y visitantes no convertidos se pierden permanentemente."]},solution:{title:"Un Sistema: Capturar, Nutrir, Probar y Convertir",intro:"Construimos el camino de conversi\xf3n completo y lo seguimos optimizando: p\xe1ginas opt-in, imanes de leads, automatizaci\xf3n email, retargeting, heatmaps y tests A/B con hip\xf3tesis que acumulan lift con el tiempo.",points:["Arquitectura de embudo mapeada a tu oferta, audiencia y duraci\xf3n del ciclo de ventas.","Landing pages de alta conversi\xf3n con imanes de leads y flujos thank-you que califican intenci\xf3n.","Secuencias email y SMS multi-paso con triggers comportamentales y CTAs de reserva.","Programa CRO estructurado con heatmaps, grabaciones de sesi\xf3n y tests A/B estad\xedsticamente v\xe1lidos."]},deliverables:{title:"Entregables Embudos y CRO",subtitle:"Cada componente de un sistema de conversi\xf3n, construido, conectado y optimizado continuamente.",items:[{title:"Estrategia y Arquitectura de Embudo",description:"Mapa de embudo, posicionamiento de oferta, targeting de audiencia y ruta de conversi\xf3n de clic a venta."},{title:"Landing Pages e Imanes de Leads",description:"Dise\xf1o opt-in, creaci\xf3n de im\xe1n de leads, thank-you pages y copy/estructura listos para CRO."},{title:"Automatizaci\xf3n Email y SMS",description:"Secuencias de nutrici\xf3n de 5 a 10 pasos con segmentaci\xf3n, triggers y CTAs de reserva o compra."},{title:"Auditor\xeda de Conversi\xf3n y Heatmaps",description:"Revisi\xf3n anal\xedtica, an\xe1lisis de drop-off, heatmaps y grabaciones con lista priorizada de fixes."},{title:"Pruebas A/B y Multivariadas",description:"Experimentos con hip\xf3tesis en titulares, CTAs, formularios, layouts y ofertas con gates de significancia."},{title:"Retargeting, Integraci\xf3n CRM y Tracking",description:"Audiencias pixel, enrutamiento formulario a CRM y tracking de conversi\xf3n en cada etapa del embudo."}]},comparison:{title:"Solo Landing Page vs. Sistema Completo Embudo + CRO",subtitle:"Qu\xe9 ganas cuando build y optimizaci\xf3n trabajan como un solo programa.",layout:"impact",columns:[{header:"Solo Landing Page"},{header:"Embudos y CRO KINEXIS",highlight:!0}],rows:[{label:"Captura de leads",values:["Un solo punto opt-in","M\xfaltiples puntos de entrada y ofertas"]},{label:"Follow-up",values:["Thank-you page, nada m\xe1s","Secuencia de nutrici\xf3n de 5 a 10 emails"]},{label:"Optimizaci\xf3n",values:["Lanzar y olvidar","Tests A/B y mejoras UX continuas"]},{label:"Tasa de conversi\xf3n",values:["1% a 3% opt-in t\xedpico","3% a 8% con embudo optimizado + testing"]},{label:"Lift acumulativo",values:["Se detiene tras lanzamiento","15% a 45% lift por test ganador"]},{label:"Inversi\xf3n",values:["$2,000 a $5,000","$5,000 build + $2,500/mes CRO"]}]},extraFaqs:[{question:"\xbfCu\xe1nto cuesta un programa de embudos y CRO?",answer:"Builds de embudo \xfanico con landing page, im\xe1n de leads y secuencia email parten en $5,000. Sistemas multi-oferta van de $10,000 a $30,000. Programas CRO continuos parten en $2,500 al mes para sitios con tr\xe1fico suficiente para tests A/B significativos."},{question:"\xbfNecesito build de embudo y CRO al mismo tiempo?",answer:"No siempre. Si ya tienes un embudo con tr\xe1fico, podemos empezar con auditor\xeda CRO y testing. Si lanzas desde cero, construimos el sistema y optimizamos desde el d\xeda uno."},{question:"\xbfCu\xe1nto tarda ver lift en conversi\xf3n?",answer:"Los builds de embudo lanzan en 4 a 8 semanas. Tests A/B suelen alcanzar significancia estad\xedstica en 2 a 4 semanas seg\xfan tr\xe1fico. La mayor\xeda de clientes ve lift medible en los primeros 60 a 90 d\xedas."},{question:"\xbfCu\xe1nto tr\xe1fico necesito para A/B testing?",answer:"Recomendamos al menos 1,000 sesiones mensuales en p\xe1ginas testeadas. Embudos con menos tr\xe1fico a\xfan se benefician de fixes UX basados en auditor\xeda e insights de heatmaps."},{question:"\xbfPueden conectar embudos a nuestro CRM?",answer:"S\xed. Integramos con HubSpot, Salesforce, ActiveCampaign, GoHighLevel y la mayor\xeda de CRMs. Los leads fluyen autom\xe1ticamente con tags de fuente y notificaciones a ventas."}]}}};function e(a,b){return d[b][a]??d.en[a]}function f(a,b,c=[]){let d=e(a,b).extraFaqs,g=new Set,h=[];for(let a of[...c,...d]){let b=a.question.toLowerCase().trim();g.has(b)||(g.add(b),h.push(a))}return h}function g(a,b){let c=e(a,b);return{title:c.metaTitle,description:c.metaDescription}}}};